"use client"

import * as React from "react"

// Theme configuration for light/dark mode
export const THEMES = { light: "", dark: ".dark" } as const

// Chart configuration type - matches shadcn/ui pattern
export type ChartConfig = {
  [key: string]: {
    label?: React.ReactNode
    icon?: React.ComponentType
  } & (
    | { color?: string; theme?: never }
    | { color?: never; theme: Record<keyof typeof THEMES, string> }
  )
}

// Default chart dimensions
export const DEFAULT_CHART_DIMENSIONS = {
  width: 600,
  height: 400,
  margin: { top: 20, right: 20, bottom: 40, left: 50 },
} as const

// Default chart colors (CSS variable references)
export const DEFAULT_CHART_COLORS = [
  "var(--chart-1)",
  "var(--chart-2)",
  "var(--chart-3)",
  "var(--chart-4)",
  "var(--chart-5)",
] as const

// Get color from config or fallback to default
export function getChartColor(
  config: ChartConfig | undefined,
  key: string,
  index: number
): string {
  if (config?.[key]?.color) {
    return config[key].color!
  }
  if (config?.[key]?.theme) {
    // Theme colors handled by CSS variables
    return `var(--color-${key})`
  }
  return DEFAULT_CHART_COLORS[index % DEFAULT_CHART_COLORS.length]
}

// Generate CSS variables from config
export function generateChartStyles(
  chartId: string,
  config: ChartConfig
): string {
  const colorConfig = Object.entries(config).filter(
    ([, cfg]) => cfg.theme || cfg.color
  )

  if (!colorConfig.length) return ""

  return Object.entries(THEMES)
    .map(
      ([theme, prefix]) => `
${prefix} [data-chart="${chartId}"] {
${colorConfig
  .map(([key, itemConfig]) => {
    const color =
      itemConfig.theme?.[theme as keyof typeof itemConfig.theme] ||
      itemConfig.color
    return color ? `  --color-${key}: ${color};` : null
  })
  .filter(Boolean)
  .join("\n")}
}`
    )
    .join("\n")
}

// Common data types
export interface ChartDataPoint {
  label: string
  value: number
  [key: string]: unknown
}

export interface ChartSeries {
  name: string
  data: ChartDataPoint[]
  color?: string
}

// Axis types
export type AxisOrientation = "top" | "right" | "bottom" | "left"
export type AxisScale = "linear" | "log" | "time" | "band" | "point"

// Common chart props
export interface BaseChartProps {
  className?: string
  config?: ChartConfig
  width?: number
  height?: number
  margin?: { top: number; right: number; bottom: number; left: number }
  showGrid?: boolean
  showTooltip?: boolean
  showLegend?: boolean
  animate?: boolean
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import {
  DEFAULT_CHART_DIMENSIONS,
  generateChartStyles,
  type ChartConfig,
} from "./chart-config"

// Chart context for sharing config across components
interface ChartContextValue {
  config: ChartConfig
  chartId: string
}

const ChartContext = React.createContext<ChartContextValue | null>(null)

export function useChart() {
  const context = React.useContext(ChartContext)
  if (!context) {
    throw new Error("useChart must be used within a ChartContainer")
  }
  return context
}

// Style injection component
function ChartStyle({ id, config }: { id: string; config: ChartConfig }) {
  const styles = generateChartStyles(id, config)
  if (!styles) return null

  return <style dangerouslySetInnerHTML={{ __html: styles }} />
}

// Main chart container
export interface ChartContainerProps extends React.HTMLAttributes<HTMLDivElement> {
  config?: ChartConfig
  children: React.ReactNode
}

export function ChartContainer({
  id,
  className,
  children,
  config = {},
  ...props
}: ChartContainerProps) {
  const uniqueId = React.useId()
  const chartId = `chart-${id || uniqueId.replace(/:/g, "")}`

  return (
    <ChartContext.Provider value={{ config, chartId }}>
      <div
        data-slot="chart"
        data-chart={chartId}
        className={cn(
          "flex aspect-video justify-center text-sm",
          "[&_.chart-grid-line]:stroke-border/40",
          "[&_.chart-axis-line]:stroke-border/60",
          "[&_.chart-axis-tick]:fill-muted-foreground",
          "[&_.chart-axis-label]:fill-muted-foreground",
          className
        )}
        {...props}
      >
        <ChartStyle id={chartId} config={config} />
        {children}
      </div>
    </ChartContext.Provider>
  )
}

// Responsive wrapper using ResizeObserver
export interface ResponsiveChartContainerProps extends ChartContainerProps {
  aspectRatio?: number
}

export function ResponsiveChartContainer({
  aspectRatio = 16 / 9,
  children,
  ...props
}: ResponsiveChartContainerProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({
    width: DEFAULT_CHART_DIMENSIONS.width,
    height: DEFAULT_CHART_DIMENSIONS.height,
  })

  React.useEffect(() => {
    if (!containerRef.current) return

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width } = entry.contentRect
        setDimensions({
          width,
          height: width / aspectRatio,
        })
      }
    })

    resizeObserver.observe(containerRef.current)
    return () => resizeObserver.disconnect()
  }, [aspectRatio])

  return (
    <div ref={containerRef} className="w-full">
      <ChartContainer {...props}>
        {React.Children.map(children, (child) => {
          if (React.isValidElement(child)) {
            return React.cloneElement(
              child as React.ReactElement<{ width?: number; height?: number }>,
              {
                width: dimensions.width,
                height: dimensions.height,
              }
            )
          }
          return child
        })}
      </ChartContainer>
    </div>
  )
}

export { ChartContext }

"use client"

import * as React from "react"
import type { ScaleBand, ScaleLinear, ScaleTime } from "d3-scale"

import { cn } from "@/lib/utils"

type AnyScale =
  | ScaleLinear<number, number>
  | ScaleBand<string>
  | ScaleTime<number, number>

export interface ChartAxisProps {
  scale: AnyScale
  orientation: "top" | "right" | "bottom" | "left"
  transform?: string
  tickCount?: number
  tickFormat?: (value: unknown) => string
  tickSize?: number
  label?: string
  className?: string
  hideAxisLine?: boolean
  hideTickMarks?: boolean
}

export function ChartAxis({
  scale,
  orientation,
  transform,
  tickCount = 5,
  tickFormat,
  tickSize = 6,
  label,
  className,
  hideAxisLine = false,
  hideTickMarks = false,
}: ChartAxisProps) {
  const isHorizontal = orientation === "top" || orientation === "bottom"
  const isLeft = orientation === "left"
  const isTop = orientation === "top"

  // Get ticks based on scale type
  const ticks = React.useMemo(() => {
    if ("ticks" in scale && typeof scale.ticks === "function") {
      return scale.ticks(tickCount)
    }
    if ("domain" in scale && typeof scale.domain === "function") {
      return scale.domain()
    }
    return []
  }, [scale, tickCount])

  // Get tick position
  const getTickPosition = (tick: unknown): number => {
    if ("bandwidth" in scale && typeof scale.bandwidth === "function") {
      const bandScale = scale as ScaleBand<string>
      return (bandScale(tick as string) ?? 0) + bandScale.bandwidth() / 2
    }
    return (scale as ScaleLinear<number, number>)(tick as number)
  }

  // Format tick value
  const formatTick = (tick: unknown): string => {
    if (tickFormat) return tickFormat(tick)
    if (tick instanceof Date) return tick.toLocaleDateString()
    if (typeof tick === "number") {
      if (Math.abs(tick) >= 1000000) return `${(tick / 1000000).toFixed(1)}M`
      if (Math.abs(tick) >= 1000) return `${(tick / 1000).toFixed(1)}K`
      return tick.toLocaleString()
    }
    return String(tick)
  }

  const range = scale.range()
  const rangeStart = Math.min(...range)
  const rangeEnd = Math.max(...range)

  return (
    <g className={cn("chart-axis", className)} transform={transform}>
      {/* Axis line */}
      {!hideAxisLine && (
        <line
          className="chart-axis-line"
          x1={isHorizontal ? rangeStart : 0}
          x2={isHorizontal ? rangeEnd : 0}
          y1={isHorizontal ? 0 : rangeStart}
          y2={isHorizontal ? 0 : rangeEnd}
          stroke="currentColor"
          strokeWidth={1}
          strokeOpacity={0.2}
        />
      )}

      {/* Ticks */}
      {ticks.map((tick, i) => {
        const position = getTickPosition(tick)
        const tickX = isHorizontal ? position : 0
        const tickY = isHorizontal ? 0 : position

        return (
          <g key={i} transform={`translate(${tickX}, ${tickY})`}>
            {/* Tick mark */}
            {!hideTickMarks && (
              <line
                className="chart-axis-tick"
                x2={isHorizontal ? 0 : isLeft ? -tickSize : tickSize}
                y2={isHorizontal ? (isTop ? -tickSize : tickSize) : 0}
                stroke="currentColor"
                strokeWidth={1}
                strokeOpacity={0.2}
              />
            )}

            {/* Tick label - LARGER TEXT */}
            <text
              className="chart-axis-label"
              style={{ fontSize: "12px" }}
              x={isHorizontal ? 0 : isLeft ? -tickSize - 8 : tickSize + 8}
              y={isHorizontal ? (isTop ? -tickSize - 8 : tickSize + 16) : 0}
              textAnchor={isHorizontal ? "middle" : isLeft ? "end" : "start"}
              dominantBaseline={isHorizontal ? "auto" : "middle"}
              fill="currentColor"
            >
              {formatTick(tick)}
            </text>
          </g>
        )
      })}

      {/* Axis label - LARGER TEXT */}
      {label && (
        <text
          className="chart-axis-label"
          style={{ fontSize: "13px", fontWeight: 500 }}
          x={isHorizontal ? (rangeStart + rangeEnd) / 2 : 0}
          y={isHorizontal ? (isTop ? -36 : 44) : (rangeStart + rangeEnd) / 2}
          textAnchor="middle"
          dominantBaseline={isHorizontal ? "auto" : "middle"}
          transform={
            !isHorizontal
              ? `rotate(-90, ${isLeft ? -48 : 48}, ${(rangeStart + rangeEnd) / 2})`
              : undefined
          }
          fill="currentColor"
        >
          {label}
        </text>
      )}
    </g>
  )
}

"use client"

import * as React from "react"
import type { ScaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface ChartGridProps {
  xScale?: ScaleLinear<number, number>
  yScale?: ScaleLinear<number, number>
  width: number
  height: number
  xTickCount?: number
  yTickCount?: number
  strokeDasharray?: string
  className?: string
}

export function ChartGrid({
  xScale,
  yScale,
  width,
  height,
  xTickCount = 5,
  yTickCount = 5,
  strokeDasharray = "3,3",
  className,
}: ChartGridProps) {
  const xTicks = xScale?.ticks(xTickCount) ?? []
  const yTicks = yScale?.ticks(yTickCount) ?? []

  return (
    <g className={cn("chart-grid", className)}>
      {/* Horizontal grid lines */}
      {yTicks.map((tick, i) => (
        <line
          key={`h-${i}`}
          className="chart-grid-line"
          x1={0}
          x2={width}
          y1={yScale!(tick)}
          y2={yScale!(tick)}
          stroke="currentColor"
          strokeDasharray={strokeDasharray}
          strokeOpacity={0.3}
        />
      ))}

      {/* Vertical grid lines */}
      {xTicks.map((tick, i) => (
        <line
          key={`v-${i}`}
          className="chart-grid-line"
          x1={xScale!(tick)}
          x2={xScale!(tick)}
          y1={0}
          y2={height}
          stroke="currentColor"
          strokeDasharray={strokeDasharray}
          strokeOpacity={0.3}
        />
      ))}
    </g>
  )
}

// Simple horizontal-only grid
export interface ChartHorizontalGridProps {
  scale: ScaleLinear<number, number>
  width: number
  tickCount?: number
  strokeDasharray?: string
  className?: string
}

export function ChartHorizontalGrid({
  scale,
  width,
  tickCount = 5,
  strokeDasharray = "",
  className,
}: ChartHorizontalGridProps) {
  const ticks = scale.ticks(tickCount)

  return (
    <g className={cn("chart-grid", className)}>
      {ticks.map((tick, i) => (
        <line
          key={i}
          className="chart-grid-line"
          x1={0}
          x2={width}
          y1={scale(tick)}
          y2={scale(tick)}
          stroke="currentColor"
          strokeDasharray={strokeDasharray}
          strokeOpacity={0.15}
        />
      ))}
    </g>
  )
}

// Simple vertical-only grid
export interface ChartVerticalGridProps {
  scale: ScaleLinear<number, number>
  height: number
  tickCount?: number
  strokeDasharray?: string
  className?: string
}

export function ChartVerticalGrid({
  scale,
  height,
  tickCount = 5,
  strokeDasharray = "3,3",
  className,
}: ChartVerticalGridProps) {
  const ticks = scale.ticks(tickCount)

  return (
    <g className={cn("chart-grid", className)}>
      {ticks.map((tick, i) => (
        <line
          key={i}
          className="chart-grid-line"
          x1={scale(tick)}
          x2={scale(tick)}
          y1={0}
          y2={height}
          stroke="currentColor"
          strokeDasharray={strokeDasharray}
          strokeOpacity={0.3}
        />
      ))}
    </g>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import type { ChartConfig } from "./chart-config"
import { useChart } from "./chart-container"

export interface TooltipData {
  label: string
  value: number | string
  color?: string
  category?: string
  [key: string]: unknown
}

export interface ChartTooltipProps {
  active?: boolean
  payload?: TooltipData | TooltipData[]
  position?: { x: number; y: number }
  className?: string
  formatter?: (value: number | string, name: string) => React.ReactNode
  labelFormatter?: (label: string) => React.ReactNode
  hideLabel?: boolean
  hideIndicator?: boolean
  indicator?: "dot" | "line" | "dashed"
}

export function ChartTooltip({
  active = true,
  payload,
  position,
  className,
  formatter,
  labelFormatter,
  hideLabel = false,
  hideIndicator = false,
  indicator = "dot",
}: ChartTooltipProps) {
  const { config } = useChart()

  if (!active || !payload) return null

  const items = Array.isArray(payload) ? payload : [payload]

  return (
    <div
      className={cn(
        "pointer-events-none absolute z-50",
        "border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl",
        "min-w-[8rem]",
        className
      )}
      style={position ? { left: position.x, top: position.y } : undefined}
    >
      {/* Label */}
      {!hideLabel && items[0]?.label && (
        <div className="mb-1 font-medium">
          {labelFormatter ? labelFormatter(items[0].label) : items[0].label}
        </div>
      )}

      {/* Items */}
      <div className="flex flex-col gap-1">
        {items.map((item, index) => {
          const itemConfig = config[item.category ?? item.label] ?? {}
          const color =
            item.color ?? itemConfig.color ?? `var(--chart-${index + 1})`

          return (
            <div
              key={index}
              className="flex items-center justify-between gap-4"
            >
              <div className="flex items-center gap-1.5">
                {/* Indicator */}
                {!hideIndicator && (
                  <div
                    className={cn(
                      "shrink-0 rounded-[2px]",
                      indicator === "dot" && "h-2.5 w-2.5",
                      indicator === "line" && "h-2.5 w-1",
                      indicator === "dashed" &&
                        "h-2.5 w-0 border-l-[1.5px] border-dashed"
                    )}
                    style={{
                      backgroundColor:
                        indicator !== "dashed" ? color : undefined,
                      borderColor: color,
                    }}
                  />
                )}

                {/* Name */}
                <span className="text-muted-foreground">
                  {itemConfig.label ?? item.category ?? item.label}
                </span>
              </div>

              {/* Value */}
              <span className="text-foreground font-mono font-medium tabular-nums">
                {formatter
                  ? formatter(item.value, item.label)
                  : typeof item.value === "number"
                    ? item.value.toLocaleString()
                    : item.value}
              </span>
            </div>
          )
        })}
      </div>
    </div>
  )
}

// Tooltip wrapper that tracks mouse position
export interface ChartTooltipWrapperProps {
  children: React.ReactNode
  content: React.ReactNode
  className?: string
}

export function ChartTooltipWrapper({
  children,
  content,
  className,
}: ChartTooltipWrapperProps) {
  const [position, setPosition] = React.useState<{
    x: number
    y: number
  } | null>(null)
  const containerRef = React.useRef<HTMLDivElement>(null)

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!containerRef.current) return
    const rect = containerRef.current.getBoundingClientRect()
    setPosition({
      x: e.clientX - rect.left + 10,
      y: e.clientY - rect.top - 10,
    })
  }

  const handleMouseLeave = () => {
    setPosition(null)
  }

  return (
    <div
      ref={containerRef}
      className={cn("relative", className)}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      {children}
      {position && (
        <div
          className="pointer-events-none absolute z-50"
          style={{ left: position.x, top: position.y }}
        >
          {content}
        </div>
      )}
    </div>
  )
}

// Simple tooltip content component
export interface ChartTooltipContentProps {
  label?: string
  value?: number | string
  color?: string
  className?: string
}

export function ChartTooltipContent({
  label,
  value,
  color,
  className,
}: ChartTooltipContentProps) {
  return (
    <div
      className={cn(
        "border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl",
        className
      )}
    >
      <div className="flex items-center gap-2">
        {color && (
          <div
            className="h-2.5 w-2.5 shrink-0 rounded-[2px]"
            style={{ backgroundColor: color }}
          />
        )}
        <span className="text-muted-foreground">{label}</span>
        {value !== undefined && (
          <span className="text-foreground font-mono font-medium tabular-nums">
            {typeof value === "number" ? value.toLocaleString() : value}
          </span>
        )}
      </div>
    </div>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import type { ChartConfig } from "./chart-config"
import { useChart } from "./chart-container"

export interface LegendItem {
  name: string
  color: string
  value?: number | string
}

export interface ChartLegendProps {
  items?: LegendItem[]
  className?: string
  position?: "top" | "bottom" | "left" | "right"
  hideIcon?: boolean
  onItemClick?: (name: string) => void
  onItemHover?: (name: string | null) => void
}

export function ChartLegend({
  items,
  className,
  position = "bottom",
  hideIcon = false,
  onItemClick,
  onItemHover,
}: ChartLegendProps) {
  const { config } = useChart()

  // Generate items from config if not provided
  const legendItems = React.useMemo(() => {
    if (items) return items

    return Object.entries(config).map(([key, value], index) => ({
      name: (value.label as string) ?? key,
      color: value.color ?? `var(--chart-${index + 1})`,
    }))
  }, [items, config])

  if (!legendItems.length) return null

  const isVertical = position === "left" || position === "right"

  return (
    <div
      className={cn(
        "flex items-center justify-center gap-6",
        isVertical && "flex-col gap-3",
        position === "top" && "pb-4",
        position === "bottom" && "pt-4",
        position === "left" && "pr-4",
        position === "right" && "pl-4",
        className
      )}
    >
      {legendItems.map((item, index) => (
        <button
          key={index}
          type="button"
          className={cn(
            "flex items-center gap-2 text-sm",
            "transition-opacity hover:opacity-80",
            onItemClick && "cursor-pointer"
          )}
          onClick={() => onItemClick?.(item.name)}
          onMouseEnter={() => onItemHover?.(item.name)}
          onMouseLeave={() => onItemHover?.(null)}
        >
          {!hideIcon && (
            <div
              className="size-3 shrink-0 rounded-sm"
              style={{ backgroundColor: item.color }}
            />
          )}
          <span className="text-foreground font-medium">{item.name}</span>
          {item.value !== undefined && (
            <span className="text-muted-foreground font-mono tabular-nums">
              {typeof item.value === "number"
                ? item.value.toLocaleString()
                : item.value}
            </span>
          )}
        </button>
      ))}
    </div>
  )
}

// Inline legend for embedding inside chart SVG
export interface ChartLegendInlineProps {
  items: LegendItem[]
  x?: number
  y?: number
  direction?: "horizontal" | "vertical"
  className?: string
}

export function ChartLegendInline({
  items,
  x = 0,
  y = 0,
  direction = "horizontal",
  className,
}: ChartLegendInlineProps) {
  const spacing = direction === "horizontal" ? 100 : 24

  return (
    <g
      className={cn("chart-legend", className)}
      transform={`translate(${x}, ${y})`}
    >
      {items.map((item, index) => (
        <g
          key={index}
          transform={
            direction === "horizontal"
              ? `translate(${index * spacing}, 0)`
              : `translate(0, ${index * spacing})`
          }
        >
          <rect width={12} height={12} rx={2} fill={item.color} />
          <text
            x={18}
            y={10}
            className="fill-foreground"
            style={{ fontSize: "13px", fontWeight: 500 }}
          >
            {item.name}
          </text>
        </g>
      ))}
    </g>
  )
}

// Legend content for use with shadcn patterns
export interface ChartLegendContentProps {
  payload?: Array<{
    value: string
    color: string
    dataKey?: string
    type?: string
  }>
  verticalAlign?: "top" | "bottom"
  hideIcon?: boolean
  nameKey?: string
  className?: string
}

export function ChartLegendContent({
  payload,
  verticalAlign = "bottom",
  hideIcon = false,
  nameKey,
  className,
}: ChartLegendContentProps) {
  const { config } = useChart()

  if (!payload?.length) return null

  return (
    <div
      className={cn(
        "flex items-center justify-center gap-6",
        verticalAlign === "top" ? "pb-4" : "pt-4",
        className
      )}
    >
      {payload
        .filter((item) => item.type !== "none")
        .map((item, index) => {
          const key = nameKey ?? item.dataKey ?? "value"
          const itemConfig = config[key] ?? {}

          return (
            <div key={index} className="flex items-center gap-2 text-sm">
              {!hideIcon && (
                <div
                  className="size-3 shrink-0 rounded-sm"
                  style={{ backgroundColor: item.color }}
                />
              )}
              <span className="text-foreground font-medium">
                {(itemConfig.label as string) ?? item.value}
              </span>
            </div>
          )
        })}
    </div>
  )
}

"use client"

import { extent, max, min } from "d3-array"
import {
  scaleBand,
  scaleLinear,
  scaleLog,
  scaleOrdinal,
  scaleTime,
} from "d3-scale"

// Re-export D3 utilities for convenience
export { scaleLinear, scaleBand, scaleTime, scaleLog, scaleOrdinal }
export { max, min, extent }

// Common scale creation utilities
export interface CreateLinearScaleOptions {
  domain: [number, number]
  range: [number, number]
  nice?: boolean
  padding?: number
}

export function createLinearScale({
  domain,
  range,
  nice = true,
  padding = 0.1,
}: CreateLinearScaleOptions) {
  const [minVal, maxVal] = domain
  const paddedDomain: [number, number] = [
    minVal - (maxVal - minVal) * padding,
    maxVal + (maxVal - minVal) * padding,
  ]

  const scale = scaleLinear().domain(paddedDomain).range(range)
  return nice ? scale.nice() : scale
}

export interface CreateBandScaleOptions {
  domain: string[]
  range: [number, number]
  padding?: number
  paddingInner?: number
  paddingOuter?: number
}

export function createBandScale({
  domain,
  range,
  padding = 0.2,
  paddingInner,
  paddingOuter,
}: CreateBandScaleOptions) {
  const scale = scaleBand().domain(domain).range(range)

  if (paddingInner !== undefined && paddingOuter !== undefined) {
    return scale.paddingInner(paddingInner).paddingOuter(paddingOuter)
  }

  return scale.padding(padding)
}

// Data processing utilities
export function getDataExtent<T>(
  data: T[],
  accessor: (d: T) => number
): [number, number] {
  const values = data.map(accessor)
  return [Math.min(...values), Math.max(...values)]
}

export function normalizeData<T extends Record<string, unknown>>(
  data: T[],
  keys: string[]
): T[] {
  const maxValues = keys.reduce(
    (acc, key) => {
      acc[key] = Math.max(...data.map((d) => Number(d[key]) || 0))
      return acc
    },
    {} as Record<string, number>
  )

  return data.map((d) => {
    const normalized = { ...d }
    keys.forEach((key) => {
      if (maxValues[key] > 0) {
        ;(normalized as Record<string, unknown>)[`${key}_normalized`] =
          (Number(d[key]) || 0) / maxValues[key]
      }
    })
    return normalized
  })
}

// Color utilities
export function interpolateColor(
  color1: string,
  color2: string,
  t: number
): string {
  // Simple linear interpolation for hex colors
  const hex1 = color1.replace("#", "")
  const hex2 = color2.replace("#", "")

  const r1 = parseInt(hex1.substring(0, 2), 16)
  const g1 = parseInt(hex1.substring(2, 4), 16)
  const b1 = parseInt(hex1.substring(4, 6), 16)

  const r2 = parseInt(hex2.substring(0, 2), 16)
  const g2 = parseInt(hex2.substring(2, 4), 16)
  const b2 = parseInt(hex2.substring(4, 6), 16)

  const r = Math.round(r1 + (r2 - r1) * t)
  const g = Math.round(g1 + (g2 - g1) * t)
  const b = Math.round(b1 + (b2 - b1) * t)

  return `#${r.toString(16).padStart(2, "0")}${g.toString(16).padStart(2, "0")}${b.toString(16).padStart(2, "0")}`
}

export function generateColorScale(
  count: number,
  baseColor?: string
): string[] {
  if (count <= 0) return []

  // Default chart colors (CSS variables)
  const defaultColors = [
    "var(--chart-1)",
    "var(--chart-2)",
    "var(--chart-3)",
    "var(--chart-4)",
    "var(--chart-5)",
  ]

  if (!baseColor) {
    return Array.from(
      { length: count },
      (_, i) => defaultColors[i % defaultColors.length]
    )
  }

  // Generate shades of the base color
  return Array.from({ length: count }, (_, i) => {
    const lightness = 0.3 + (0.5 * i) / (count - 1 || 1)
    return `hsl(from ${baseColor} h s ${lightness * 100}%)`
  })
}

// Animation utilities
export function easeOutCubic(t: number): number {
  return 1 - Math.pow(1 - t, 3)
}

export function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2
}

export function easeOutElastic(t: number): number {
  const c4 = (2 * Math.PI) / 3
  return t === 0
    ? 0
    : t === 1
      ? 1
      : Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * c4) + 1
}

// Number formatting utilities
export function formatNumber(value: number, decimals = 0): string {
  if (Math.abs(value) >= 1e9) {
    return `${(value / 1e9).toFixed(decimals)}B`
  }
  if (Math.abs(value) >= 1e6) {
    return `${(value / 1e6).toFixed(decimals)}M`
  }
  if (Math.abs(value) >= 1e3) {
    return `${(value / 1e3).toFixed(decimals)}K`
  }
  return value.toFixed(decimals)
}

export function formatPercent(value: number, decimals = 1): string {
  return `${(value * 100).toFixed(decimals)}%`
}

export function formatCurrency(
  value: number,
  currency = "USD",
  locale = "en-US"
): string {
  return new Intl.NumberFormat(locale, {
    style: "currency",
    currency,
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  }).format(value)
}

// Geometry utilities
export function polarToCartesian(
  centerX: number,
  centerY: number,
  radius: number,
  angleInDegrees: number
): { x: number; y: number } {
  const angleInRadians = ((angleInDegrees - 90) * Math.PI) / 180
  return {
    x: centerX + radius * Math.cos(angleInRadians),
    y: centerY + radius * Math.sin(angleInRadians),
  }
}

export function describeArc(
  x: number,
  y: number,
  radius: number,
  startAngle: number,
  endAngle: number
): string {
  const start = polarToCartesian(x, y, radius, endAngle)
  const end = polarToCartesian(x, y, radius, startAngle)
  const largeArcFlag = endAngle - startAngle <= 180 ? 0 : 1

  return [
    "M",
    start.x,
    start.y,
    "A",
    radius,
    radius,
    0,
    largeArcFlag,
    0,
    end.x,
    end.y,
  ].join(" ")
}

// SVG path utilities
export function linePath(points: Array<{ x: number; y: number }>): string {
  if (points.length === 0) return ""

  return points.map((p, i) => `${i === 0 ? "M" : "L"} ${p.x} ${p.y}`).join(" ")
}

export function smoothLinePath(
  points: Array<{ x: number; y: number }>,
  smoothing = 0.2
): string {
  if (points.length < 2) return linePath(points)

  const line = (
    pointA: { x: number; y: number },
    pointB: { x: number; y: number }
  ) => {
    const lengthX = pointB.x - pointA.x
    const lengthY = pointB.y - pointA.y
    return {
      length: Math.sqrt(Math.pow(lengthX, 2) + Math.pow(lengthY, 2)),
      angle: Math.atan2(lengthY, lengthX),
    }
  }

  const controlPoint = (
    current: { x: number; y: number },
    previous: { x: number; y: number } | undefined,
    next: { x: number; y: number } | undefined,
    reverse?: boolean
  ) => {
    const p = previous ?? current
    const n = next ?? current
    const l = line(p, n)
    const angle = l.angle + (reverse ? Math.PI : 0)
    const length = l.length * smoothing
    return {
      x: current.x + Math.cos(angle) * length,
      y: current.y + Math.sin(angle) * length,
    }
  }

  return points.reduce((path, point, i, arr) => {
    if (i === 0) return `M ${point.x} ${point.y}`

    const cp1 = controlPoint(arr[i - 1], arr[i - 2], point)
    const cp2 = controlPoint(point, arr[i - 1], arr[i + 1], true)

    return `${path} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${point.x} ${point.y}`
  }, "")
}

