                        className="flex items-center gap-2 text-sm"
                      >
                        <div
                          className="size-2 rounded-full"
                          style={{ backgroundColor: entry.color }}
                        />
                        <span className="text-muted-foreground">
                          {entry.name}:
                        </span>
                        <span style={{ color: entry.color }}>
                          {valueFormatter(entry.value as number)}
                        </span>
                      </div>
                    ))}
                  </div>
                )
              }}
            />
          )}

          {series.map((s) => (
            <Bar
              key={s.dataKey}
              dataKey={s.dataKey}
              name={s.name}
              fill={s.color}
              radius={barRadius}
              stackId={s.stackId}
              maxBarSize={40}
            />
          ))}
        </RechartsBarChart>
      </ResponsiveContainer>

      {showLegend && (
        <div className="mt-4 flex flex-wrap items-center justify-center gap-4">
          {series.map((s) => (
            <div key={s.dataKey} className="flex items-center gap-2 text-sm">
              <div
                className="size-3 rounded-sm"
                style={{ backgroundColor: s.color }}
              />
              <span className="text-muted-foreground">{s.name}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Area,
  CartesianGrid,
  ComposedChart,
  Line,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts"

import { cn } from "@/lib/utils"

export interface AreaChartDataPoint {
  label: string
  value: number
  [key: string]: unknown
}

export interface AreaChartProps {
  data: AreaChartDataPoint[]
  className?: string
  color?: string
  gradientFrom?: string
  gradientTo?: string
  gradientOpacity?: [number, number]
  showDots?: boolean
  showGrid?: boolean
  showTooltip?: boolean
  showCursor?: boolean
  valueFormatter?: (value: number) => string
  labelFormatter?: (label: string) => string
  yAxisDomain?: [number, number]
  yAxisTicks?: number[]
  animate?: boolean
  strokeWidth?: number
  dotRadius?: number
  xAxisAngle?: number
  aspectRatio?: number
  curveType?: "linear" | "monotone" | "step"
}

export function AreaChart({
  data,
  className,
  color = "#2563eb",
  gradientFrom = "#2563eb",
  gradientTo = "#93c5fd",
  gradientOpacity = [0.8, 0.1],
  showDots = false,
  showGrid = true,
  showTooltip = true,
  showCursor = true,
  valueFormatter = (value) => `${value}%`,
  labelFormatter = (label) => label,
  yAxisDomain,
  yAxisTicks,
  animate = true,
  strokeWidth = 2,
  dotRadius = 4,
  xAxisAngle = 0,
  aspectRatio = 2,
  curveType = "linear",
}: AreaChartProps) {
  const gradientId = React.useId().replace(/:/g, "")
  const patternId = React.useId().replace(/:/g, "")

  // Calculate domain from data if not provided
  const calculatedDomain = React.useMemo(() => {
    if (yAxisDomain) return yAxisDomain
    const values = data.map((d) => d.value)
    const min = Math.min(...values)
    const max = Math.max(...values)
    const padding = (max - min) * 0.1
    return [
      Math.max(0, Math.floor((min - padding) / 10) * 10),
      Math.ceil((max + padding) / 10) * 10,
    ] as [number, number]
  }, [data, yAxisDomain])

  // Calculate ticks if not provided
  const calculatedTicks = React.useMemo(() => {
    if (yAxisTicks) return yAxisTicks
    const [min, max] = calculatedDomain
    const step = (max - min) / 4
    return Array.from({ length: 5 }, (_, i) => Math.round(min + step * i))
  }, [calculatedDomain, yAxisTicks])

  return (
    <div className={cn("w-full", className)}>
      <ResponsiveContainer width="100%" aspect={aspectRatio}>
        <ComposedChart
          data={data}
          margin={{
            top: 20,
            right: 30,
            left: 10,
            bottom: xAxisAngle === 0 ? 20 : 60,
          }}
        >
          <defs>
            {/* Gradient fill - stronger fade */}
            <linearGradient
              id={`gradient-${gradientId}`}
              x1="0"
              y1="0"
              x2="0"
              y2="1"
            >
              <stop
                offset="0%"
                stopColor={gradientFrom}
                stopOpacity={gradientOpacity[0]}
              />
              <stop
                offset="100%"
                stopColor={gradientTo}
                stopOpacity={gradientOpacity[1]}
              />
            </linearGradient>

            {/* Dotted pattern overlay */}
            <pattern
              id={`pattern-${patternId}`}
              x="0"
              y="0"
              width="6"
              height="6"
              patternUnits="userSpaceOnUse"
            >
              <circle cx="1.5" cy="1.5" r="0.75" fill="rgba(255,255,255,0.3)" />
            </pattern>
          </defs>

          {/* Grid */}
          {showGrid && (
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={true}
              horizontal={true}
              stroke="hsl(var(--border))"
              strokeOpacity={0.5}
            />
          )}

          {/* Y-Axis */}
          <YAxis
            domain={calculatedDomain}
            ticks={calculatedTicks}
            tickFormatter={valueFormatter}
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={4}
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(payload.value)}
              </text>
            )}
            width={50}
          />

          {/* X-Axis */}
          <XAxis
            dataKey="label"
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={16}
                textAnchor="middle"
                className="fill-muted-foreground text-xs"
              >
                {labelFormatter(payload.value)}
              </text>
            )}
            height={xAxisAngle === 0 ? 30 : 60}
            interval={0}
          />

          {/* Tooltip with cursor line */}
          {showTooltip && (
            <Tooltip
              cursor={
                showCursor
                  ? {
                      stroke: "hsl(var(--muted-foreground))",
                      strokeWidth: 1,
                      strokeDasharray: "4 4",
                    }
                  : false
              }
              content={({ active, payload, label }) => {
                if (!active || !payload?.length) return null
                return (
                  <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                    <p className="text-foreground text-sm font-medium">
                      {labelFormatter(label)}
                    </p>
                    {payload.map((entry, index) => (
                      <p
                        key={index}
                        className="text-sm"
                        style={{ color: entry.color }}
                      >
                        {entry.name}: {valueFormatter(entry.value as number)}
                      </p>
                    ))}
                  </div>
                )
              }}
            />
          )}

          {/* Area fill with gradient */}
          <Area
            type={curveType}
            dataKey="value"
            stroke="none"
            fill={`url(#gradient-${gradientId})`}
            fillOpacity={1}
            isAnimationActive={animate}
            animationBegin={0}
            animationDuration={1500}
            animationEasing="ease-out"
          />

          {/* Dotted pattern overlay */}
          <Area
            type={curveType}
            dataKey="value"
            stroke="none"
            fill={`url(#pattern-${patternId})`}
            fillOpacity={1}
            isAnimationActive={animate}
            animationBegin={0}
            animationDuration={1500}
            animationEasing="ease-out"
          />

          {/* Line on top with dots */}
          <Line
            type={curveType}
            dataKey="value"
            stroke={color}
            strokeWidth={strokeWidth}
            dot={
              showDots
                ? {
                    r: dotRadius,
                    fill: "hsl(var(--background))",
                    stroke: color,
                    strokeWidth: 2,
                  }
                : false
            }
            activeDot={{
              r: 4,
              fill: color,
              stroke: "hsl(var(--background))",
              strokeWidth: 2,
            }}
            isAnimationActive={animate}
            animationBegin={200}
            animationDuration={1800}
            animationEasing="ease-out"
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  )
}

// Helper function to generate chart data
export function generateAreaChartData(
  labels: string[],
  values: number[]
): AreaChartDataPoint[] {
  return labels.map((label, index) => ({
    label,
    value: values[index] ?? 0,
  }))
}

// ============================================
// Multi-Series Area Chart
// ============================================

export interface MultiAreaChartSeries {
  name: string
  dataKey: string
  color: string
  gradientFrom?: string
  gradientTo?: string
}

export interface MultiAreaChartDataPoint {
  label: string
  [key: string]: string | number
}

export interface MultiAreaChartProps {
  data: MultiAreaChartDataPoint[]
  series: MultiAreaChartSeries[]
  className?: string
  showGrid?: boolean
  showTooltip?: boolean
  showCursor?: boolean
  showLegend?: boolean
  valueFormatter?: (value: number) => string
  labelFormatter?: (label: string) => string
  yAxisDomain?: [number, number]
  yAxisTicks?: number[]
  animate?: boolean
  strokeWidth?: number
  xAxisAngle?: number
  aspectRatio?: number
  curveType?: "linear" | "monotone" | "step"
  stacked?: boolean
  gradientOpacity?: [number, number]
}

export function MultiAreaChart({
  data,
  series,
  className,
  showGrid = true,
  showTooltip = true,
  showCursor = true,
  showLegend = true,
  valueFormatter = (value) => `${value}`,
  labelFormatter = (label) => label,
  yAxisDomain,
  yAxisTicks,
  animate = true,
  strokeWidth = 2,
  xAxisAngle = 0,
  aspectRatio = 2,
  curveType = "monotone",
  stacked = false,
  gradientOpacity = [0.6, 0.1],
}: MultiAreaChartProps) {
  const baseId = React.useId().replace(/:/g, "")

  // Calculate domain from all series data
  const calculatedDomain = React.useMemo(() => {
    if (yAxisDomain) return yAxisDomain
    const allValues = data.flatMap((d) =>
      series.map((s) => (d[s.dataKey] as number) || 0)
    )
    const min = Math.min(...allValues)
    const max = Math.max(...allValues)
    const padding = (max - min) * 0.1
    return [
      Math.max(0, Math.floor((min - padding) / 10) * 10),
      Math.ceil((max + padding) / 10) * 10,
    ] as [number, number]
  }, [data, series, yAxisDomain])

  const calculatedTicks = React.useMemo(() => {
    if (yAxisTicks) return yAxisTicks
    const [min, max] = calculatedDomain
    const step = (max - min) / 4
    return Array.from({ length: 5 }, (_, i) => Math.round(min + step * i))
  }, [calculatedDomain, yAxisTicks])

  return (
    <div className={cn("w-full", className)}>
      <ResponsiveContainer width="100%" aspect={aspectRatio}>
        <ComposedChart
          data={data}
          margin={{
            top: 20,
            right: 30,
            left: 10,
            bottom: xAxisAngle === 0 ? 20 : 60,
          }}
        >
          <defs>
            {series.map((s, i) => (
              <linearGradient
                key={s.dataKey}
                id={`gradient-${baseId}-${i}`}
                x1="0"
                y1="0"
                x2="0"
                y2="1"
              >
                <stop
                  offset="0%"
                  stopColor={s.gradientFrom || s.color}
                  stopOpacity={gradientOpacity[0]}
                />
                <stop
                  offset="100%"
                  stopColor={s.gradientTo || s.color}
                  stopOpacity={gradientOpacity[1]}
                />
              </linearGradient>
            ))}
            {/* Dot pattern overlay */}
            <pattern
              id={`pattern-${baseId}`}
              x="0"
              y="0"
              width="6"
              height="6"
              patternUnits="userSpaceOnUse"
            >
              <circle
                cx="1.5"
                cy="1.5"
                r="0.75"
                fill="rgba(255,255,255,0.25)"
              />
            </pattern>
          </defs>

          {showGrid && (
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={true}
              horizontal={true}
              stroke="hsl(var(--border))"
              strokeOpacity={0.5}
            />
          )}

          <YAxis
            domain={calculatedDomain}
            ticks={calculatedTicks}
            tickFormatter={valueFormatter}
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={4}
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(payload.value)}
              </text>
            )}
            width={50}
          />

          <XAxis
            dataKey="label"
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={16}
                textAnchor="middle"
                className="fill-muted-foreground text-xs"
              >
                {labelFormatter(payload.value)}
              </text>
            )}
            height={xAxisAngle === 0 ? 30 : 60}
            interval={0}
          />

          {showTooltip && (
            <Tooltip
              cursor={
                showCursor
                  ? {
                      stroke: "hsl(var(--muted-foreground))",
                      strokeWidth: 1,
                      strokeDasharray: "4 4",
                    }
                  : false
              }
              content={({ active, payload, label }) => {
                if (!active || !payload?.length) return null
                return (
                  <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                    <p className="text-foreground mb-1 text-sm font-medium">
                      {labelFormatter(label)}
                    </p>
                    {payload.map((entry, index) => (
                      <div
                        key={index}
                        className="flex items-center gap-2 text-sm"
                      >
                        <div
                          className="size-2 rounded-full"
                          style={{ backgroundColor: entry.color }}
                        />
                        <span className="text-muted-foreground">
                          {entry.name}:
                        </span>
                        <span style={{ color: entry.color }}>
                          {valueFormatter(entry.value as number)}
                        </span>
                      </div>
                    ))}
                  </div>
                )
              }}
            />
          )}

          {/* Render areas in reverse order so first series is on top */}
          {[...series].reverse().map((s, i) => (
            <Area
              key={`${s.dataKey}-fill`}
              type={curveType}
              dataKey={s.dataKey}
              name={s.name}
              stroke={s.color}
              strokeWidth={strokeWidth}
              fill={`url(#gradient-${baseId}-${series.length - 1 - i})`}
              fillOpacity={1}
              stackId={stacked ? "stack" : undefined}
              isAnimationActive={animate}
              animationBegin={i * 100}
              animationDuration={1500}
              animationEasing="ease-out"
              activeDot={{
                r: 4,
                fill: s.color,
                stroke: "hsl(var(--background))",
                strokeWidth: 2,
              }}
            />
          ))}

          {/* Dot pattern overlay for each series */}
          {[...series].reverse().map((s, i) => (
            <Area
              key={`${s.dataKey}-pattern`}
              type={curveType}
              dataKey={s.dataKey}
              stroke="none"
              fill={`url(#pattern-${baseId})`}
              fillOpacity={1}
              stackId={stacked ? "stack-pattern" : undefined}
              isAnimationActive={animate}
              animationBegin={i * 100}
              animationDuration={1500}
              animationEasing="ease-out"
              legendType="none"
              tooltipType="none"
            />
          ))}
        </ComposedChart>
      </ResponsiveContainer>

      {/* Legend */}
      {showLegend && (
        <div className="mt-4 flex flex-wrap items-center justify-center gap-4">
          {series.map((s) => (
            <div key={s.dataKey} className="flex items-center gap-2 text-sm">
              <div
                className="size-3 rounded-sm"
                style={{ backgroundColor: s.color }}
              />
              <span className="text-muted-foreground">{s.name}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartGrid } from "../chart-grid"
import { ChartLegend, type LegendItem } from "../chart-legend"
import { ChartTooltipContent } from "../chart-tooltip"

export interface ScatterChartDataPoint {
  x: number
  y: number
  size?: number
  label?: string
  [key: string]: unknown
}

export interface ScatterChartSeries {
  name: string
  data: ScatterChartDataPoint[]
  color?: string
  symbol?: "circle" | "square" | "triangle" | "diamond" | "cross"
  size?: number
}

export interface ScatterChartProps extends BaseChartProps {
  data: ScatterChartSeries[]
  xAxisLabel?: string
  yAxisLabel?: string
  sizeRange?: [number, number]
  symbol?: "circle" | "square" | "triangle" | "diamond" | "cross"
  size?: number
  showTrendLine?: boolean
}

// SVG path generators for different symbols
const symbolPaths: Record<string, (size: number) => string> = {
  circle: (s) => {
    const r = s / 2
    return `M 0,${-r} A ${r},${r} 0 1,1 0,${r} A ${r},${r} 0 1,1 0,${-r}`
  },
  square: (s) => {
    const h = s / 2
    return `M ${-h},${-h} L ${h},${-h} L ${h},${h} L ${-h},${h} Z`
  },
  triangle: (s) => {
    const h = s / 2
    return `M 0,${-h} L ${h},${h} L ${-h},${h} Z`
  },
  diamond: (s) => {
    const h = s / 2
    return `M 0,${-h} L ${h},0 L 0,${h} L ${-h},0 Z`
  },
  cross: (s) => {
    const h = s / 2
    const w = s / 6
    return `M ${-w},${-h} L ${w},${-h} L ${w},${-w} L ${h},${-w} L ${h},${w} L ${w},${w} L ${w},${h} L ${-w},${h} L ${-w},${w} L ${-h},${w} L ${-h},${-w} L ${-w},${-w} Z`
  },
}

export function ScatterChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 40, left: 50 },
  showGrid = true,
  showTooltip = true,
  showLegend = true,
  xAxisLabel,
  yAxisLabel,
  sizeRange = [6, 20],
  symbol = "circle",
  size = 8,
  showTrendLine = false,
}: ScatterChartProps) {
  const [hoveredPoint, setHoveredPoint] = React.useState<{
    seriesIndex: number
    pointIndex: number
    x: number
    y: number
  } | null>(null)
  const [hoveredSeries, setHoveredSeries] = React.useState<string | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Flatten all data points for scales
  const allPoints = data.flatMap((series) => series.data)

  // Scales
  const xScale = React.useMemo(() => {
    const xValues = allPoints.map((d) => d.x)
    const xMin = Math.min(...xValues)
    const xMax = Math.max(...xValues)
    const padding = (xMax - xMin) * 0.1
    return scaleLinear()
      .domain([xMin - padding, xMax + padding])
      .range([0, innerWidth])
      .nice()
  }, [allPoints, innerWidth])

  const yScale = React.useMemo(() => {
    const yValues = allPoints.map((d) => d.y)
    const yMin = Math.min(...yValues)
    const yMax = Math.max(...yValues)
    const padding = (yMax - yMin) * 0.1
    return scaleLinear()
      .domain([yMin - padding, yMax + padding])
      .range([innerHeight, 0])
      .nice()
  }, [allPoints, innerHeight])

  // Size scale for bubble chart
  const sizeScale = React.useMemo(() => {
    const sizeValues = allPoints.map((d) => d.size ?? 1)
    const sizeMin = Math.min(...sizeValues)
    const sizeMax = Math.max(...sizeValues)
    return scaleLinear().domain([sizeMin, sizeMax]).range(sizeRange)
  }, [allPoints, sizeRange])

  // Calculate trend line (simple linear regression)
  const trendLine = React.useMemo(() => {
    if (!showTrendLine) return null

    const n = allPoints.length
    if (n < 2) return null

    const sumX = allPoints.reduce((acc, d) => acc + d.x, 0)
    const sumY = allPoints.reduce((acc, d) => acc + d.y, 0)
    const sumXY = allPoints.reduce((acc, d) => acc + d.x * d.y, 0)
    const sumX2 = allPoints.reduce((acc, d) => acc + d.x * d.x, 0)

    const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX)
    const intercept = (sumY - slope * sumX) / n

    const xDomain = xScale.domain()
    return {
      x1: xDomain[0],
      y1: slope * xDomain[0] + intercept,
      x2: xDomain[1],
      y2: slope * xDomain[1] + intercept,
    }
  }, [allPoints, showTrendLine, xScale])

  // Legend items
  const legendItems: LegendItem[] = data.map((series, i) => ({
    name: series.name,
    color:
      series.color ?? config?.[series.name]?.color ?? `var(--chart-${i + 1})`,
  }))

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartGrid
              xScale={xScale}
              yScale={yScale}
              width={innerWidth}
              height={innerHeight}
            />
          )}

          {/* Trend line */}
          {trendLine && (
            <line
              x1={xScale(trendLine.x1)}
              y1={yScale(trendLine.y1)}
              x2={xScale(trendLine.x2)}
              y2={yScale(trendLine.y2)}
              stroke="currentColor"
              strokeWidth={2}
              strokeDasharray="6,4"
              className="text-muted-foreground/50"
            />
          )}

          {/* Points */}
          {data.map((series, seriesIndex) => {
            const seriesColor =
              series.color ??
              config?.[series.name]?.color ??
              `var(--chart-${seriesIndex + 1})`
            const seriesSymbol = series.symbol ?? symbol
            const isSeriesHovered =
              hoveredSeries === null || hoveredSeries === series.name

            return series.data.map((point, pointIndex) => {
              const pointSize =
                point.size !== undefined
                  ? sizeScale(point.size)
                  : (series.size ?? size)
              const isHovered =
                hoveredPoint?.seriesIndex === seriesIndex &&
                hoveredPoint?.pointIndex === pointIndex

              return (
                <g
                  key={`${seriesIndex}-${pointIndex}`}
                  transform={`translate(${xScale(point.x)}, ${yScale(point.y)})`}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    !isSeriesHovered && "opacity-30"
                  )}
                  onMouseEnter={() =>
                    setHoveredPoint({
                      seriesIndex,
                      pointIndex,
                      x: xScale(point.x),
                      y: yScale(point.y),
                    })
                  }
                  onMouseLeave={() => setHoveredPoint(null)}
                >
                  <path
                    d={symbolPaths[seriesSymbol](
                      isHovered ? pointSize * 1.3 : pointSize
                    )}
                    fill={seriesColor}
                    stroke="white"
                    strokeWidth={1}
                  />
                </g>
              )
            })
          })}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredPoint && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: margin.left + hoveredPoint.x + 15,
            top: margin.top + hoveredPoint.y - 10,
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="mb-1 font-medium">
              {data[hoveredPoint.seriesIndex].data[hoveredPoint.pointIndex]
                .label ?? data[hoveredPoint.seriesIndex].name}
            </div>
            <div className="text-muted-foreground">
              x:{" "}
              {data[hoveredPoint.seriesIndex].data[
                hoveredPoint.pointIndex
              ].x.toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              y:{" "}
              {data[hoveredPoint.seriesIndex].data[
                hoveredPoint.pointIndex
              ].y.toLocaleString()}
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      {showLegend && data.length > 1 && (
        <ChartLegend items={legendItems} onItemHover={setHoveredSeries} />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { arc, pie } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartLegend, type LegendItem } from "../chart-legend"
import { ChartTooltipContent } from "../chart-tooltip"

export interface PieChartDataPoint {
  label: string
  value: number
  color?: string
  [key: string]: unknown
}

export interface PieChartProps extends BaseChartProps {
  data: PieChartDataPoint[]
  innerRadius?: number
  outerRadius?: number
  padAngle?: number
  cornerRadius?: number
  startAngle?: number
  endAngle?: number
  sortValues?: boolean
  showLabels?: boolean
  labelType?: "percent" | "value" | "label"
}

export function PieChart({
  data,
  config,
  className,
  width = 400,
  height = 400,
  margin = { top: 20, right: 20, bottom: 20, left: 20 },
  showTooltip = true,
  showLegend = true,
  innerRadius = 0,
  outerRadius: outerRadiusProp,
  padAngle = 0.02,
  cornerRadius = 4,
  startAngle = 0,
  endAngle = 2 * Math.PI,
  sortValues = false,
  showLabels = false,
  labelType = "percent",
}: PieChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const outerRadius = outerRadiusProp ?? radius

  // Calculate total
  const total = data.reduce((sum, d) => sum + d.value, 0)

  // Create pie generator
  const pieGenerator = pie<PieChartDataPoint>()
    .value((d) => d.value)
    .padAngle(padAngle)
    .startAngle(startAngle)
    .endAngle(endAngle)
    .sort(sortValues ? (a, b) => b.value - a.value : null)

  // Create arc generator
  const arcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius)
    .cornerRadius(cornerRadius)

  // Hover arc (slightly larger)
  const hoverArcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius * 1.05)
    .cornerRadius(cornerRadius)

  // Label arc
  const labelArcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(outerRadius * 0.7)
    .outerRadius(outerRadius * 0.7)

  const arcs = pieGenerator(data)

  // Get color for segment
  const getColor = (d: PieChartDataPoint, index: number): string => {
    return (
      d.color ?? config?.[d.label]?.color ?? `var(--chart-${(index % 5) + 1})`
    )
  }

  // Format label
  const formatLabel = (d: PieChartDataPoint): string => {
    switch (labelType) {
      case "percent":
        return `${((d.value / total) * 100).toFixed(1)}%`
      case "value":
        return d.value.toLocaleString()
      case "label":
        return d.label
      default:
        return ""
    }
  }

  // Legend items
  const legendItems: LegendItem[] = data.map((d, i) => ({
    name: d.label,
    color: getColor(d, i),
    value: d.value,
  }))

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g
          transform={`translate(${margin.left + innerWidth / 2}, ${margin.top + innerHeight / 2})`}
        >
          {arcs.map((arcData, index) => {
            const isHovered = hoveredIndex === index
            const color = getColor(data[index], index)

            return (
              <g key={index}>
                {/* Pie segment */}
                <path
                  d={
                    (isHovered ? hoverArcGenerator : arcGenerator)(arcData) ??
                    ""
                  }
                  fill={color}
                  stroke="white"
                  strokeWidth={2}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-50"
                  )}
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                />

                {/* Labels */}
                {showLabels && (
                  <text
                    transform={`translate(${labelArcGenerator.centroid(arcData)})`}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    className="pointer-events-none fill-white text-[10px] font-medium"
                    style={{ textShadow: "0 1px 2px rgba(0,0,0,0.5)" }}
                  >
                    {formatLabel(data[index])}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div className="pointer-events-none absolute top-1/2 left-1/2 z-50 -translate-x-1/2 -translate-y-1/2">
          <div className="border-border/50 bg-background rounded-lg border px-3 py-2 text-sm shadow-xl">
            <div className="flex items-center gap-2">
              <div
                className="h-3 w-3 rounded-sm"
                style={{
                  backgroundColor: getColor(data[hoveredIndex], hoveredIndex),
                }}
              />
              <span className="font-medium">{data[hoveredIndex].label}</span>
            </div>
            <div className="text-muted-foreground mt-1">
              {data[hoveredIndex].value.toLocaleString()} (
              {((data[hoveredIndex].value / total) * 100).toFixed(1)}%)
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      {showLegend && (
        <ChartLegend
          items={legendItems}
          onItemHover={(name) => {
            const index = data.findIndex((d) => d.label === name)
            setHoveredIndex(index >= 0 ? index : null)
          }}
        />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { interpolate } from "d3-interpolate"
import { arc, pie } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface DonutChartDataPoint {
  label: string
  value: number
  color?: string
  [key: string]: unknown
}

export interface DonutChartProps extends BaseChartProps {
  data: DonutChartDataPoint[]
  /** Inner radius as ratio (0-1) of outer radius. 0.6 = 60% hollow */
  innerRadius?: number
  /** Padding angle between segments in radians */
  padAngle?: number
  /** Corner radius for rounded segments */
  cornerRadius?: number
  /** Starting angle in radians (0 = top) */
  startAngle?: number
  /** Ending angle in radians */
  endAngle?: number
  /** Sort segments by value */
  sortValues?: boolean
  /** Show percentage labels on segments */
  showLabels?: boolean
  /** Show label lines for small segments */
  showLabelLines?: boolean
  /** Minimum angle (radians) to show inline label */
  minLabelAngle?: number
  /** Center text (top line) */
  centerLabel?: React.ReactNode
  /** Center value (large text) */
  centerValue?: React.ReactNode
  /** Animate on mount */
  animate?: boolean
  /** Animation duration in ms */
  animationDuration?: number
  /** Active/selected segment index */
  activeIndex?: number
  /** Callback when segment is clicked */
  onSegmentClick?: (data: DonutChartDataPoint, index: number) => void
  /** Value formatter for tooltip and labels */
  valueFormatter?: (value: number, total: number) => string
  /** Show total in center when nothing hovered */
  showTotal?: boolean
  /** Variant style */
  variant?: "default" | "gradient" | "separated"
}

// Default colors
const DEFAULT_COLORS = [
  "hsl(var(--chart-1))",
  "hsl(var(--chart-2))",
  "hsl(var(--chart-3))",
  "hsl(var(--chart-4))",
  "hsl(var(--chart-5))",
]

export function DonutChart({
  data,
  config,
  className,
  width = 400,
  height = 400,
  margin = { top: 40, right: 40, bottom: 40, left: 40 },
  showTooltip = true,
  showLegend = true,
  innerRadius: innerRadiusRatio = 0.6,
  padAngle = 0.02,
  cornerRadius = 4,
  startAngle = -Math.PI / 2,
  endAngle = Math.PI * 1.5,
  sortValues = false,
  showLabels = false,
  showLabelLines = true,
  minLabelAngle = 0.4,
  centerLabel,
  centerValue,
  animate = true,
  animationDuration = 750,
  activeIndex: controlledActiveIndex,
  onSegmentClick,
  valueFormatter = (value, total) => `${((value / total) * 100).toFixed(1)}%`,
  showTotal = true,
  variant = "default",
}: DonutChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [animationProgress, setAnimationProgress] = React.useState(
    animate ? 0 : 1
  )
  const [tooltipData, setTooltipData] = React.useState<{
    x: number
    y: number
    data: DonutChartDataPoint
    index: number
  } | null>(null)

  const containerRef = React.useRef<HTMLDivElement>(null)
  const gradientId = React.useId().replace(/:/g, "")

  // Animation
  React.useEffect(() => {
    if (!animate) return

    const startTime = Date.now()
    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      setAnimationProgress(eased)

      if (progress < 1) {
        requestAnimationFrame(animateFrame)
      }
    }
    requestAnimationFrame(animateFrame)
  }, [animate, animationDuration])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const outerRadius = Math.min(innerWidth, innerHeight) / 2
  const innerRadius = outerRadius * Math.max(0, Math.min(1, innerRadiusRatio))

  // Calculate total
  const total = data.reduce((sum, d) => sum + d.value, 0)

  // Active index (controlled or hovered)
  const activeIndex = controlledActiveIndex ?? hoveredIndex

  // Create pie generator
  const pieGenerator = pie<DonutChartDataPoint>()
    .value((d) => d.value)
    .padAngle(variant === "separated" ? 0.06 : padAngle)
    .startAngle(startAngle)
    .endAngle(interpolate(startAngle, endAngle)(animationProgress))
    .sort(sortValues ? (a, b) => b.value - a.value : null)

  // Create arc generators
  const arcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius)
    .cornerRadius(cornerRadius)

  // Hover arc (slightly larger)
  const hoverArcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(innerRadius - 4)
    .outerRadius(outerRadius + 8)
    .cornerRadius(cornerRadius)

  // Label arc (for positioning)
  const labelArcGenerator = arc<ReturnType<typeof pieGenerator>[number]>()
    .innerRadius(outerRadius + 15)
    .outerRadius(outerRadius + 15)

  const arcs = pieGenerator(data)

  // Get color for segment
  const getColor = (d: DonutChartDataPoint, index: number): string => {
    if (d.color) return d.color
    if (config?.[d.label]?.color) return config[d.label].color
    return DEFAULT_COLORS[index % DEFAULT_COLORS.length]
  }

  // Handle mouse events
  const handleMouseMove = (
    e: React.MouseEvent,
    data: DonutChartDataPoint,
    index: number
  ) => {
    if (!showTooltip) return
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      setTooltipData({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
        data,
        index,
      })
    }
  }

  // Determine if label should be outside
  const shouldShowOutsideLabel = (
    arcData: ReturnType<typeof pieGenerator>[number]
  ) => {
    const angle = arcData.endAngle - arcData.startAngle
    return showLabels && showLabelLines && angle < minLabelAngle && angle > 0.1
  }

  // Center content
  const displayedCenterValue =
    activeIndex !== null
      ? valueFormatter(data[activeIndex].value, total)
      : (centerValue ?? (showTotal ? total.toLocaleString() : null))

  const displayedCenterLabel =
    activeIndex !== null
      ? data[activeIndex].label
      : (centerLabel ?? (showTotal ? "Total" : null))

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <div ref={containerRef} className="relative">
        <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
          {/* Gradient definitions */}
          {variant === "gradient" && (
            <defs>
              {data.map((d, i) => {
                const color = getColor(d, i)
                return (
                  <linearGradient
                    key={i}
                    id={`gradient-${gradientId}-${i}`}
                    x1="0%"
                    y1="0%"
                    x2="100%"
                    y2="100%"
                  >
                    <stop offset="0%" stopColor={color} stopOpacity={1} />
                    <stop offset="100%" stopColor={color} stopOpacity={0.6} />
                  </linearGradient>
                )
              })}
            </defs>
          )}

          <g
            transform={`translate(${margin.left + innerWidth / 2}, ${margin.top + innerHeight / 2})`}
          >
            {/* Background ring */}
            <circle
              r={(outerRadius + innerRadius) / 2}
              fill="none"
              stroke="hsl(var(--muted))"
              strokeWidth={outerRadius - innerRadius}
              strokeOpacity={0.15}
            />

            {/* Donut segments */}
            {arcs.map((arcData, index) => {
              const isActive = activeIndex === index
              const d = data[index]
              const color = getColor(d, index)
              const fill =
                variant === "gradient"
                  ? `url(#gradient-${gradientId}-${index})`
                  : color

              return (
                <g key={index}>
                  {/* Shadow for active segment */}
                  {isActive && (
                    <path
                      d={hoverArcGenerator(arcData) ?? ""}
                      fill="black"
                      fillOpacity={0.1}
                      filter="blur(8px)"
                      className="pointer-events-none"
                    />
                  )}

                  {/* Main segment */}
                  <path
                    d={
                      (isActive ? hoverArcGenerator : arcGenerator)(arcData) ??
                      ""
                    }
                    fill={fill}
                    stroke={
                      variant === "separated"
                        ? "hsl(var(--background))"
                        : "none"
                    }
                    strokeWidth={variant === "separated" ? 3 : 0}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      activeIndex !== null && !isActive && "opacity-50"
                    )}
                    style={{
                      filter: isActive ? "brightness(1.1)" : undefined,
                    }}
                    onMouseEnter={() => setHoveredIndex(index)}
                    onMouseMove={(e) => handleMouseMove(e, d, index)}
                    onMouseLeave={() => {
                      setHoveredIndex(null)
                      setTooltipData(null)
                    }}
                    onClick={() => onSegmentClick?.(d, index)}
                  />

                  {/* Inline labels for large segments */}
                  {showLabels &&
                    arcData.endAngle - arcData.startAngle >= minLabelAngle && (
                      <text
                        transform={`translate(${arcGenerator.centroid(arcData)})`}
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="pointer-events-none text-[11px] font-semibold"
                        fill="white"
                        style={{ textShadow: "0 1px 2px rgba(0,0,0,0.5)" }}
                      >
                        {valueFormatter(d.value, total)}
                      </text>
                    )}

                  {/* Outside labels with lines for small segments */}
                  {shouldShowOutsideLabel(arcData) && (
                    <g className="pointer-events-none">
                      <polyline
                        points={(() => {
                          const posA = arcGenerator.centroid(arcData)
                          const posB = labelArcGenerator.centroid(arcData)
                          const midAngle =
                            (arcData.startAngle + arcData.endAngle) / 2
                          const posC = [
                            posB[0] + (midAngle < Math.PI ? 10 : -10),
                            posB[1],
                          ]
                          return `${posA[0]},${posA[1]} ${posB[0]},${posB[1]} ${posC[0]},${posC[1]}`
                        })()}
                        fill="none"
                        stroke="hsl(var(--muted-foreground))"
                        strokeWidth={1}
                        strokeOpacity={0.5}
                      />
                      <text
                        transform={`translate(${labelArcGenerator.centroid(arcData)})`}
                        textAnchor={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? "start"
                            : "end"
                        }
                        dx={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? 15
                            : -15
                        }
                        dominantBaseline="middle"
                        className="fill-muted-foreground text-[10px]"
                      >
                        {d.label}
                      </text>
                    </g>
                  )}
                </g>
              )
            })}

            {/* Center content */}
            <g className="pointer-events-none">
              {displayedCenterValue && (
                <text
                  textAnchor="middle"
                  dominantBaseline="middle"
                  y={displayedCenterLabel ? -6 : 0}
                  className="fill-foreground text-2xl font-bold"
                  style={{ fontSize: innerRadius * 0.35 }}
                >
                  {displayedCenterValue}
                </text>
              )}
              {displayedCenterLabel && (
                <text
                  textAnchor="middle"
                  dominantBaseline="middle"
                  y={displayedCenterValue ? innerRadius * 0.2 : 0}
                  className="fill-muted-foreground text-sm"
                  style={{ fontSize: innerRadius * 0.15 }}
                >
                  {displayedCenterLabel}
                </text>
              )}
            </g>
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && tooltipData && (
          <div
            className="pointer-events-none absolute z-50 -translate-x-1/2 -translate-y-full"
            style={{
              left: tooltipData.x,
              top: tooltipData.y - 10,
            }}
          >
            <div className="bg-popover text-popover-foreground rounded-lg border px-3 py-2 shadow-lg">
              <div className="flex items-center gap-2">
                <div
                  className="h-3 w-3 rounded-full"
                  style={{
                    backgroundColor: getColor(
                      tooltipData.data,
                      tooltipData.index
                    ),
                  }}
                />
                <span className="font-medium">{tooltipData.data.label}</span>
              </div>
              <div className="mt-1 text-sm">
                <span className="text-muted-foreground">Value: </span>
                <span className="font-semibold">
                  {tooltipData.data.value.toLocaleString()}
                </span>
                <span className="text-muted-foreground ml-2">
                  ({valueFormatter(tooltipData.data.value, total)})
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Legend */}
        {showLegend && (
          <div className="mt-4 flex flex-wrap justify-center gap-4">
            {data.map((d, i) => (
              <button
                key={i}
                className={cn(
                  "flex items-center gap-2 rounded-md px-2 py-1 text-sm transition-all",
                  "hover:bg-muted/50",
                  activeIndex === i && "bg-muted"
                )}
                onMouseEnter={() => setHoveredIndex(i)}
                onMouseLeave={() => setHoveredIndex(null)}
                onClick={() => onSegmentClick?.(d, i)}
              >
                <div
                  className="h-3 w-3 rounded-full"
                  style={{ backgroundColor: getColor(d, i) }}
                />
                <span className="text-muted-foreground">{d.label}</span>
                <span className="font-medium">
                  {valueFormatter(d.value, total)}
                </span>
              </button>
            ))}
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { bin } from "d3-array"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"
import { ChartTooltipContent } from "../chart-tooltip"

export interface HistogramChartProps extends BaseChartProps {
  data: number[]
  bins?: number
  xAxisLabel?: string
  yAxisLabel?: string
  color?: string
  barPadding?: number
  showDensity?: boolean
  normalized?: boolean
}

export function HistogramChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 40, left: 50 },
  showGrid = true,
  showTooltip = true,
  bins = 20,
  xAxisLabel,
  yAxisLabel,
  color,
  barPadding = 1,
  showDensity = false,
  normalized = false,
}: HistogramChartProps) {
  const [hoveredBin, setHoveredBin] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create histogram bins
  const histogram = React.useMemo(() => {
    const [minVal, maxVal] = [Math.min(...data), Math.max(...data)]
    const binGenerator = bin().domain([minVal, maxVal]).thresholds(bins)
    return binGenerator(data)
  }, [data, bins])

  // Calculate density if needed
  const binData = React.useMemo(() => {
    const total = data.length
    return histogram.map((b) => ({
      x0: b.x0!,
      x1: b.x1!,
      count: b.length,
      density: b.length / total / (b.x1! - b.x0!),
      percent: (b.length / total) * 100,
    }))
  }, [histogram, data.length])

  // Scales
  const xScale = React.useMemo(() => {
    return scaleLinear()
      .domain([binData[0]?.x0 ?? 0, binData[binData.length - 1]?.x1 ?? 1])
      .range([0, innerWidth])
  }, [binData, innerWidth])

  const yScale = React.useMemo(() => {
    const maxY = showDensity
      ? Math.max(...binData.map((b) => b.density))
      : normalized
        ? Math.max(...binData.map((b) => b.percent))
        : Math.max(...binData.map((b) => b.count))
    return scaleLinear()
      .domain([0, maxY * 1.1])
      .range([innerHeight, 0])
      .nice()
  }, [binData, innerHeight, showDensity, normalized])

  const barColor = color ?? config?.histogram?.color ?? "var(--chart-1)"

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid scale={yScale} width={innerWidth} />
          )}

          {/* Bars */}
          {binData.map((b, index) => {
            const barX = xScale(b.x0)
            const barWidth = xScale(b.x1) - xScale(b.x0) - barPadding
            const yValue = showDensity
              ? b.density
              : normalized
                ? b.percent
                : b.count
            const barY = yScale(yValue)
            const barHeight = innerHeight - barY

            return (
              <rect
                key={index}
                x={barX}
                y={barY}
                width={Math.max(0, barWidth)}
                height={Math.max(0, barHeight)}
                fill={barColor}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredBin !== null && hoveredBin !== index && "opacity-50"
                )}
                onMouseEnter={() => setHoveredBin(index)}
                onMouseLeave={() => setHoveredBin(null)}
              />
            )
          })}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis
            scale={yScale}
            orientation="left"
            label={
              yAxisLabel ??
              (showDensity ? "Density" : normalized ? "Percentage" : "Count")
            }
          />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredBin !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              xScale((binData[hoveredBin].x0 + binData[hoveredBin].x1) / 2),
            top:
              margin.top +
              yScale(
                showDensity
                  ? binData[hoveredBin].density
                  : normalized
                    ? binData[hoveredBin].percent
                    : binData[hoveredBin].count
              ) -
              10,
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {binData[hoveredBin].x0.toFixed(2)} -{" "}
              {binData[hoveredBin].x1.toFixed(2)}
            </div>
            <div className="text-muted-foreground">
              Count: {binData[hoveredBin].count}
            </div>
            <div className="text-muted-foreground">
              {binData[hoveredBin].percent.toFixed(1)}%
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { max, median, min, quantile } from "d3-array"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface BoxPlotDataPoint {
  label: string
  values: number[]
  color?: string
}

export interface BoxPlotStats {
  label: string
  min: number
  q1: number
  median: number
  q3: number
  max: number
  outliers: number[]
  color?: string
}

export interface BoxPlotChartProps {
  data: BoxPlotDataPoint[] | BoxPlotStats[]
  className?: string
  color?: string
  showGrid?: boolean
  showTooltip?: boolean
  orientation?: "vertical" | "horizontal"
  boxWidth?: number
  showOutliers?: boolean
  whiskerType?: "minmax" | "iqr"
  aspectRatio?: number
  valueFormatter?: (value: number) => string
}

function isStats(
  data: BoxPlotDataPoint[] | BoxPlotStats[]
): data is BoxPlotStats[] {
  return data.length > 0 && "median" in data[0]
}

function calculateStats(
  values: number[],
  whiskerType: "minmax" | "iqr"
): Omit<BoxPlotStats, "label" | "color"> {
  const sorted = [...values].sort((a, b) => a - b)
  const q1 = quantile(sorted, 0.25) ?? 0
  const med = median(sorted) ?? 0
  const q3 = quantile(sorted, 0.75) ?? 0
  const iqr = q3 - q1

  let minVal: number, maxVal: number
  let outliers: number[] = []

  if (whiskerType === "iqr") {
    const lowerFence = q1 - 1.5 * iqr
    const upperFence = q3 + 1.5 * iqr
    minVal = min(sorted.filter((v) => v >= lowerFence)) ?? sorted[0]
    maxVal =
      max(sorted.filter((v) => v <= upperFence)) ?? sorted[sorted.length - 1]
    outliers = sorted.filter((v) => v < lowerFence || v > upperFence)
  } else {
    minVal = min(sorted) ?? 0
    maxVal = max(sorted) ?? 0
  }

  return { min: minVal, q1, median: med, q3, max: maxVal, outliers }
}

export function BoxPlotChart({
  data,
  className,
  color = "#2563eb",
  showGrid = true,
  showTooltip = true,
  orientation = "vertical",
  boxWidth = 0.6,
  showOutliers = true,
  whiskerType = "iqr",
  aspectRatio = 2,
  valueFormatter = (value) => value.toFixed(0),
}: BoxPlotChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  const { width, height } = dimensions
  const margin = { top: 20, right: 20, bottom: 40, left: 50 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)
  const isVertical = orientation === "vertical"

  // Calculate stats if raw values provided
  const statsData: BoxPlotStats[] = React.useMemo(() => {
    if (isStats(data)) return data
    return data.map((d) => ({
      label: d.label,
      color: d.color,
      ...calculateStats(d.values, whiskerType),
    }))
  }, [data, whiskerType])

  // Category scale
  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(statsData.map((d) => d.label))
      .range(isVertical ? [0, innerWidth] : [0, innerHeight])
      .padding(0.3)
  }, [statsData, innerWidth, innerHeight, isVertical])

  // Value scale
  const valueScale = React.useMemo(() => {
    const allValues = statsData.flatMap((d) => [d.min, d.max, ...d.outliers])
    const minV = Math.min(...allValues)
    const maxV = Math.max(...allValues)
    const padding = (maxV - minV) * 0.1
    return scaleLinear()
      .domain([Math.floor(minV - padding), Math.ceil(maxV + padding)])
      .range(isVertical ? [innerHeight, 0] : [0, innerWidth])
      .nice()
  }, [statsData, innerWidth, innerHeight, isVertical])

  const actualBoxWidth = categoryScale.bandwidth() * boxWidth
  const ticks = valueScale.ticks(5)

  if (width === 0) {
    return <div ref={containerRef} className={cn("w-full", className)} />
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <>
              {/* Horizontal grid lines */}
              {ticks.map((tick) => (
                <line
                  key={`h-${tick}`}
                  x1={0}
                  x2={innerWidth}
                  y1={isVertical ? valueScale(tick) : 0}
                  y2={isVertical ? valueScale(tick) : innerHeight}
                  stroke="hsl(var(--border))"
                  strokeOpacity={0.5}
                  strokeDasharray="3 3"
                />
              ))}
              {/* Vertical grid lines */}
              {statsData.map((d) => {
                const x =
                  (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
                return (
                  <line
                    key={`v-${d.label}`}
                    x1={x}
                    x2={x}
                    y1={0}
                    y2={innerHeight}
                    stroke="hsl(var(--border))"
                    strokeOpacity={0.5}
                    strokeDasharray="3 3"
                  />
                )
              })}
            </>
          )}

          {/* Box plots */}
          {statsData.map((d, index) => {
            const boxColor = d.color ?? color
            const center =
              (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
            const boxOffset = actualBoxWidth / 2
            const isHovered = hoveredIndex === index

            if (isVertical) {
              return (
                <g
                  key={d.label}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-40"
                  )}
                  onMouseEnter={(e) => {
                    setHoveredIndex(index)
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseMove={(e) => {
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseLeave={() => setHoveredIndex(null)}
                >
                  {/* Whisker line */}
                  <line
                    x1={center}
                    x2={center}
                    y1={valueScale(d.min)}
                    y2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={1.5}
                  />

                  {/* Min whisker */}
                  <line
                    x1={center - boxOffset * 0.5}
                    x2={center + boxOffset * 0.5}
                    y1={valueScale(d.min)}
                    y2={valueScale(d.min)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Max whisker */}
                  <line
                    x1={center - boxOffset * 0.5}
                    x2={center + boxOffset * 0.5}
                    y1={valueScale(d.max)}
                    y2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Box */}
                  <rect
                    x={center - boxOffset}
                    y={valueScale(d.q3)}
                    width={actualBoxWidth}
                    height={Math.max(0, valueScale(d.q1) - valueScale(d.q3))}
                    fill={boxColor}
                    fillOpacity={0.2}
                    stroke={boxColor}
                    strokeWidth={2}
                    rx={4}
                  />

                  {/* Median line */}
                  <line
                    x1={center - boxOffset}
                    x2={center + boxOffset}
                    y1={valueScale(d.median)}
                    y2={valueScale(d.median)}
                    stroke={boxColor}
                    strokeWidth={3}
                  />

                  {/* Outliers */}
                  {showOutliers &&
                    d.outliers.map((outlier, i) => (
                      <circle
                        key={i}
                        cx={center}
                        cy={valueScale(outlier)}
                        r={4}
                        fill={boxColor}
                        fillOpacity={0.5}
                        stroke={boxColor}
                        strokeWidth={1.5}
                      />
                    ))}
                </g>
              )
            } else {
              // Horizontal orientation
              return (
                <g
                  key={d.label}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-40"
                  )}
                  onMouseEnter={(e) => {
                    setHoveredIndex(index)
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseMove={(e) => {
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseLeave={() => setHoveredIndex(null)}
                >
                  {/* Whisker line */}
                  <line
                    y1={center}
                    y2={center}
                    x1={valueScale(d.min)}
                    x2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={1.5}
                  />

                  {/* Min whisker */}
                  <line
                    y1={center - boxOffset * 0.5}
                    y2={center + boxOffset * 0.5}
                    x1={valueScale(d.min)}
                    x2={valueScale(d.min)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Max whisker */}
                  <line
                    y1={center - boxOffset * 0.5}
                    y2={center + boxOffset * 0.5}
                    x1={valueScale(d.max)}
                    x2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Box */}
                  <rect
                    y={center - boxOffset}
                    x={valueScale(d.q1)}
                    height={actualBoxWidth}
                    width={Math.max(0, valueScale(d.q3) - valueScale(d.q1))}
                    fill={boxColor}
                    fillOpacity={0.2}
                    stroke={boxColor}
                    strokeWidth={2}
                    rx={4}
                  />

                  {/* Median line */}
                  <line
                    y1={center - boxOffset}
                    y2={center + boxOffset}
                    x1={valueScale(d.median)}
                    x2={valueScale(d.median)}
                    stroke={boxColor}
                    strokeWidth={3}
                  />

                  {/* Outliers */}
                  {showOutliers &&
                    d.outliers.map((outlier, i) => (
                      <circle
                        key={i}
                        cy={center}
                        cx={valueScale(outlier)}
                        r={4}
                        fill={boxColor}
                        fillOpacity={0.5}
                        stroke={boxColor}
                        strokeWidth={1.5}
                      />
                    ))}
                </g>
              )
            }
          })}

          {/* X Axis */}
          <g transform={`translate(0, ${innerHeight})`}>
            {statsData.map((d) => {
              const x =
                (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
              return (
                <text
                  key={d.label}
                  x={x}
                  y={24}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {d.label}
                </text>
              )
            })}
          </g>

          {/* Y Axis */}
          <g>
            {ticks.map((tick) => (
              <text
                key={tick}
                x={-12}
                y={valueScale(tick)}
                dy="0.32em"
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}
          </g>
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: tooltipPos.x + 10,
            top: tooltipPos.y - 10,
            transform: "translateY(-100%)",
          }}
        >
          <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
            <p className="text-foreground mb-1 text-sm font-medium">
              {statsData[hoveredIndex].label}
            </p>
            <div className="space-y-0.5 text-sm">
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Max</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].max)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Q3</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].q3)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Median</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].median)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Q1</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].q1)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Min</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].min)}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { bin, max, median, quantile } from "d3-array"
import { scaleBand, scaleLinear } from "d3-scale"
import { area, curveCardinal } from "d3-shape"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"

export interface ViolinChartData {
  label: string
  values: number[]
  color?: string
}

export interface ViolinChartProps extends BaseChartProps {
  data: ViolinChartData[]
  orientation?: "vertical" | "horizontal"
  bandwidth?: number
  showBoxPlot?: boolean
  showMedian?: boolean
  resolution?: number
  xAxisLabel?: string
  yAxisLabel?: string
}

// Kernel density estimation
function kde(
  values: number[],
  domain: [number, number],
  bandwidth: number,
  resolution: number
): Array<{ x: number; y: number }> {
  const [minVal, maxVal] = domain
  const step = (maxVal - minVal) / resolution
  const points: Array<{ x: number; y: number }> = []

  for (let x = minVal; x <= maxVal; x += step) {
    let density = 0
    for (const v of values) {
      const u = (x - v) / bandwidth
      // Gaussian kernel
      density += Math.exp(-0.5 * u * u) / Math.sqrt(2 * Math.PI)
    }
    density /= values.length * bandwidth
    points.push({ x, y: density })
  }

  return points
}

export function ViolinChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 40, left: 50 },
  showGrid = true,
  showTooltip = true,
  orientation = "vertical",
  bandwidth: bandwidthProp,
  showBoxPlot = true,
  showMedian = true,
  resolution = 50,
  xAxisLabel,
  yAxisLabel,
}: ViolinChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const isVertical = orientation === "vertical"

  // Calculate all stats and KDE
  const processedData = React.useMemo(() => {
    const allValues = data.flatMap((d) => d.values)
    const globalMin = Math.min(...allValues)
    const globalMax = Math.max(...allValues)
    const domain: [number, number] = [globalMin, globalMax]

    return data.map((d) => {
      const sorted = [...d.values].sort((a, b) => a - b)
      const q1 = quantile(sorted, 0.25) ?? 0
      const med = median(sorted) ?? 0
      const q3 = quantile(sorted, 0.75) ?? 0
      const iqr = q3 - q1

      // Silverman's rule of thumb for bandwidth
      const std = Math.sqrt(
        d.values.reduce((acc, v) => acc + Math.pow(v - med, 2), 0) /
          d.values.length
      )
      const bw =
        bandwidthProp ??
        0.9 * Math.min(std, iqr / 1.34) * Math.pow(d.values.length, -0.2)

      const density = kde(d.values, domain, bw, resolution)
      const maxDensity = max(density, (p) => p.y) ?? 1

      return {
        label: d.label,
        color: d.color,
        values: d.values,
        density,
        maxDensity,
        q1,
        median: med,
        q3,
        min: Math.min(...sorted),
        max: Math.max(...sorted),
      }
    })
  }, [data, bandwidthProp, resolution])

  // Category scale
  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.label))
      .range(isVertical ? [0, innerWidth] : [0, innerHeight])
      .padding(0.2)
  }, [data, innerWidth, innerHeight, isVertical])

  // Value scale
  const valueScale = React.useMemo(() => {
    const allValues = data.flatMap((d) => d.values)
    const minV = Math.min(...allValues)
    const maxV = Math.max(...allValues)
    const padding = (maxV - minV) * 0.1
    return scaleLinear()
      .domain([minV - padding, maxV + padding])
      .range(isVertical ? [innerHeight, 0] : [0, innerWidth])
      .nice()
  }, [data, innerWidth, innerHeight, isVertical])

  // Density scale (for violin width)
  const maxMaxDensity = Math.max(...processedData.map((d) => d.maxDensity))
  const densityScale = scaleLinear()
    .domain([0, maxMaxDensity])
    .range([0, categoryScale.bandwidth() / 2])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid
              scale={
                isVertical
                  ? valueScale
                  : scaleLinear()
                      .domain(valueScale.domain())
                      .range([innerHeight, 0])
              }
              width={innerWidth}
            />
          )}

          {/* Violins */}
          {processedData.map((d, index) => {
            const color =
              d.color ??
              config?.[d.label]?.color ??
              `var(--chart-${(index % 5) + 1})`
            const center =
              (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
            const isHovered = hoveredIndex === index

            // Create violin path
            const violinArea = area<{ x: number; y: number }>().curve(
              curveCardinal
            )

            if (isVertical) {
              violinArea
                .x0((p) => center - densityScale(p.y))
                .x1((p) => center + densityScale(p.y))
                .y((p) => valueScale(p.x))
            } else {
              violinArea
                .y0((p) => center - densityScale(p.y))
                .y1((p) => center + densityScale(p.y))
                .x((p) => valueScale(p.x))
            }

            return (
              <g
                key={d.label}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-50"
                )}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Violin shape */}
                <path
                  d={violinArea(d.density) ?? ""}
                  fill={color}
                  fillOpacity={0.3}
                  stroke={color}
                  strokeWidth={1.5}
                />

                {/* Box plot overlay */}
                {showBoxPlot && (
                  <>
                    {isVertical ? (
                      <>
                        {/* Box */}
                        <rect
                          x={center - 4}
                          y={valueScale(d.q3)}
                          width={8}
                          height={valueScale(d.q1) - valueScale(d.q3)}
                          fill={color}
                          fillOpacity={0.6}
                          rx={1}
                        />
                        {/* Whiskers */}
                        <line
                          x1={center}
                          x2={center}
                          y1={valueScale(d.min)}
                          y2={valueScale(d.q1)}
                          stroke={color}
                          strokeWidth={1}
                        />
                        <line
                          x1={center}
                          x2={center}
                          y1={valueScale(d.q3)}
                          y2={valueScale(d.max)}
                          stroke={color}
                          strokeWidth={1}
                        />
                      </>
                    ) : (
                      <>
                        {/* Box */}
                        <rect
                          y={center - 4}
                          x={valueScale(d.q1)}
                          height={8}
                          width={valueScale(d.q3) - valueScale(d.q1)}
                          fill={color}
                          fillOpacity={0.6}
                          rx={1}
                        />
                        {/* Whiskers */}
                        <line
                          y1={center}
                          y2={center}
                          x1={valueScale(d.min)}
                          x2={valueScale(d.q1)}
                          stroke={color}
                          strokeWidth={1}
                        />
                        <line
                          y1={center}
                          y2={center}
                          x1={valueScale(d.q3)}
                          x2={valueScale(d.max)}
                          stroke={color}
                          strokeWidth={1}
                        />
                      </>
                    )}
                  </>
                )}

                {/* Median point */}
                {showMedian && (
                  <circle
                    cx={isVertical ? center : valueScale(d.median)}
                    cy={isVertical ? valueScale(d.median) : center}
                    r={4}
                    fill="white"
                    stroke={color}
                    strokeWidth={2}
                  />
                )}
              </g>
            )
          })}

          {/* Axes */}
          <ChartAxis
            scale={isVertical ? categoryScale : valueScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />
          <ChartAxis
            scale={isVertical ? valueScale : categoryScale}
            orientation="left"
            label={yAxisLabel}
          />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              (isVertical
                ? (categoryScale(processedData[hoveredIndex].label) ?? 0) +
                  categoryScale.bandwidth() / 2
                : valueScale(processedData[hoveredIndex].median)),
            top: margin.top + 10,
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {processedData[hoveredIndex].label}
            </div>
            <div className="text-muted-foreground">
              n: {processedData[hoveredIndex].values.length}
            </div>
            <div className="text-muted-foreground">
              Median: {processedData[hoveredIndex].median.toFixed(2)}
            </div>
            <div className="text-muted-foreground">
              Q1-Q3: {processedData[hoveredIndex].q1.toFixed(2)} -{" "}
              {processedData[hoveredIndex].q3.toFixed(2)}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface CandlestickDataPoint {
  date: string | Date
  open: number
  high: number
  low: number
  close: number
}

export interface CandlestickChartProps {
  data: CandlestickDataPoint[]
  className?: string
  upColor?: string
  downColor?: string
  showGrid?: boolean
  showTooltip?: boolean
  hollowCandles?: boolean
  aspectRatio?: number
  valueFormatter?: (value: number) => string
  dateFormatter?: (date: Date) => string
}

export function CandlestickChart({
  data,
  className,
  upColor = "#22c55e",
  downColor = "#ef4444",
  showGrid = true,
  showTooltip = true,
  hollowCandles = false,
  aspectRatio = 2.5,
  valueFormatter = (value) => `$${value.toFixed(0)}`,
  dateFormatter = (date) =>
    date.toLocaleDateString("en-US", { month: "short" }),
}: CandlestickChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  const { width, height } = dimensions
  const margin = { top: 20, right: 20, bottom: 40, left: 50 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)

  // X Scale
  const xScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => String(d.date)))
      .range([0, innerWidth])
      .padding(0.2)
  }, [data, innerWidth])

  // Y Scale (price)
  const yScale = React.useMemo(() => {
    const allPrices = data.flatMap((d) => [d.high, d.low])
    const minPrice = Math.min(...allPrices)
    const maxPrice = Math.max(...allPrices)
    const padding = (maxPrice - minPrice) * 0.1
    return scaleLinear()
      .domain([Math.max(0, minPrice - padding), maxPrice + padding])
      .range([innerHeight, 0])
      .nice()
  }, [data, innerHeight])

  const candleWidth = xScale.bandwidth() * 0.8
  const ticks = yScale.ticks(5)

  // Get unique months for x-axis labels
  const monthLabels = React.useMemo(() => {
    const labels: { date: string; x: number }[] = []
    let lastMonth = -1
    data.forEach((d) => {
      const date = new Date(d.date)
      const month = date.getMonth()
      if (month !== lastMonth) {
        labels.push({
          date: String(d.date),
          x: (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2,
        })
        lastMonth = month
      }
    })
    return labels
  }, [data, xScale])

  if (width === 0) {
    return <div ref={containerRef} className={cn("w-full", className)} />
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid - dashed lines like area chart */}
          {showGrid && (
            <>
              {/* Horizontal grid lines */}
              {ticks.map((tick) => (
                <line
                  key={`h-${tick}`}
                  x1={0}
                  x2={innerWidth}
                  y1={yScale(tick)}
                  y2={yScale(tick)}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
              {/* Vertical grid lines at month boundaries */}
              {monthLabels.map((label, i) => (
                <line
                  key={`v-${i}`}
                  x1={label.x}
                  x2={label.x}
                  y1={0}
                  y2={innerHeight}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
            </>
          )}

          {/* Candlesticks */}
          {data.map((d, index) => {
            const isUp = d.close >= d.open
            const color = isUp ? upColor : downColor
            const bodyTop = isUp ? d.close : d.open
            const bodyBottom = isUp ? d.open : d.close
            const x = (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2
            const isHovered = hoveredIndex === index

            // For hollow candles: up candles are hollow, down are filled
            const fill = hollowCandles ? (isUp ? "transparent" : color) : color

            return (
              <g
                key={index}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-40"
                )}
                onMouseEnter={(e) => {
                  setHoveredIndex(index)
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseMove={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Wick (high to low) */}
                <line
                  x1={x}
                  x2={x}
                  y1={yScale(d.high)}
                  y2={yScale(d.low)}
                  stroke={color}
                  strokeWidth={1}
                />

                {/* Body */}
                <rect
                  x={x - candleWidth / 2}
                  y={yScale(bodyTop)}
                  width={candleWidth}
                  height={Math.max(1, yScale(bodyBottom) - yScale(bodyTop))}
                  fill={fill}
                  stroke={color}
                  strokeWidth={1}
                  rx={1}
                />
              </g>
            )
          })}

          {/* X Axis - Month labels */}
          <g transform={`translate(0, ${innerHeight})`}>
            {monthLabels.map((label, i) => {
              const date = new Date(label.date)
              return (
                <text
                  key={i}
                  x={label.x}
                  y={24}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {dateFormatter(date)}
                </text>
              )
            })}
          </g>

          {/* Y Axis */}
          <g>
            {ticks.map((tick) => (
              <text
                key={tick}
                x={-12}
                y={yScale(tick)}
                dy="0.32em"
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}
          </g>
        </g>
      </svg>

      {/* Tooltip - auto-adjusts position based on available space */}
      {showTooltip &&
        hoveredIndex !== null &&
        (() => {
          const tooltipWidth = 140
          const tooltipHeight = 120
          const padding = 10

          // Determine horizontal position
          const spaceOnRight = width - tooltipPos.x
          const showOnLeft = spaceOnRight < tooltipWidth + padding * 2

          // Determine vertical position
          const spaceOnTop = tooltipPos.y
          const showBelow = spaceOnTop < tooltipHeight + padding

          return (
            <div
              className="pointer-events-none absolute z-50"
              style={{
                left: showOnLeft
                  ? tooltipPos.x - padding
                  : tooltipPos.x + padding,
                top: showBelow
                  ? tooltipPos.y + padding
                  : tooltipPos.y - padding,
                transform: `translate(${showOnLeft ? "-100%" : "0"}, ${showBelow ? "0" : "-100%"})`,
              }}
            >
              <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                <p className="text-foreground mb-1 text-sm font-medium">
                  {new Date(data[hoveredIndex].date).toLocaleDateString(
                    "en-US",
                    {
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    }
                  )}
                </p>
                <div className="grid grid-cols-2 gap-x-4 gap-y-0.5 text-sm">
                  <span className="text-muted-foreground">Open</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].open)}
                  </span>
                  <span className="text-muted-foreground">High</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].high)}
                  </span>
                  <span className="text-muted-foreground">Low</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].low)}
                  </span>
                  <span className="text-muted-foreground">Close</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].close)}
                  </span>
                </div>
              </div>
            </div>
          )
        })()}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"
import { ChartTooltipContent } from "../chart-tooltip"

export interface WaterfallDataPoint {
  label: string
  value: number
  isTotal?: boolean
  isSubtotal?: boolean
}

export interface WaterfallChartProps extends BaseChartProps {
  data: WaterfallDataPoint[]
  positiveColor?: string
  negativeColor?: string
  totalColor?: string
  connectorColor?: string
  showConnector?: boolean
  barRadius?: number
  xAxisLabel?: string
  yAxisLabel?: string
}

export function WaterfallChart({
  data,
  config,
  className,
  width = 700,
  height = 400,
  margin = { top: 20, right: 20, bottom: 60, left: 60 },
  showGrid = true,
  showTooltip = true,
  positiveColor = "var(--chart-2)",
  negativeColor = "var(--chart-1)",
  totalColor = "var(--chart-3)",
  connectorColor = "currentColor",
  showConnector = true,
  barRadius = 2,
  xAxisLabel,
  yAxisLabel,
}: WaterfallChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Calculate cumulative values
  const processedData = React.useMemo(() => {
    let runningTotal = 0
    return data.map((d, i) => {
      const start = d.isTotal || d.isSubtotal ? 0 : runningTotal
      const end = d.isTotal || d.isSubtotal ? d.value : runningTotal + d.value
      runningTotal = end
      return {
        ...d,
        start,
        end,
        isPositive: d.value >= 0,
      }
    })
  }, [data])

  // Scales
  const xScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.label))
      .range([0, innerWidth])
      .padding(0.3)
  }, [data, innerWidth])

  const yScale = React.useMemo(() => {
    const allValues = processedData.flatMap((d) => [d.start, d.end])
    const minVal = Math.min(0, ...allValues)
    const maxVal = Math.max(0, ...allValues)
    const padding = (maxVal - minVal) * 0.1
    return scaleLinear()
      .domain([minVal - padding, maxVal + padding])
      .range([innerHeight, 0])
      .nice()
  }, [processedData, innerHeight])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid scale={yScale} width={innerWidth} />
          )}

          {/* Zero line */}
          <line
            x1={0}
            x2={innerWidth}
            y1={yScale(0)}
            y2={yScale(0)}
            stroke="currentColor"
            strokeWidth={1}
            className="text-border"
          />

          {/* Bars and connectors */}
          {processedData.map((d, index) => {
            const x = xScale(d.label) ?? 0
            const barWidth = xScale.bandwidth()
            const y1 = yScale(Math.max(d.start, d.end))
            const y2 = yScale(Math.min(d.start, d.end))
            const barHeight = Math.abs(y2 - y1)

            const color =
              d.isTotal || d.isSubtotal
                ? totalColor
                : d.isPositive
                  ? positiveColor
                  : negativeColor

            const isHovered = hoveredIndex === index

            return (
              <g key={index}>
                {/* Connector line */}
                {showConnector && index > 0 && !d.isTotal && (
                  <line
                    x1={xScale(processedData[index - 1].label)! + barWidth}
                    x2={x}
                    y1={yScale(processedData[index - 1].end)}
                    y2={yScale(processedData[index - 1].end)}
                    stroke={connectorColor}
                    strokeWidth={1}
                    strokeDasharray="3,3"
                    className="text-muted-foreground/50"
                  />
                )}

                {/* Bar */}
                <rect
                  x={x}
                  y={y1}
                  width={barWidth}
                  height={Math.max(1, barHeight)}
                  fill={color}
                  rx={barRadius}
                  ry={barRadius}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-50"
                  )}
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                />

                {/* Value label */}
                <text
                  x={x + barWidth / 2}
                  y={d.value >= 0 ? y1 - 5 : y2 + 14}
                  textAnchor="middle"
                  className="fill-foreground pointer-events-none text-[10px] font-medium"
                >
                  {d.value >= 0 ? "+" : ""}
                  {d.value.toLocaleString()}
                </text>
              </g>
            )
          })}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              (xScale(processedData[hoveredIndex].label) ?? 0) +
              xScale.bandwidth() / 2,
            top:
              margin.top +
              yScale(
                Math.max(
                  processedData[hoveredIndex].start,
                  processedData[hoveredIndex].end
                )
              ) -
              50,
          }}
        >
          <div className="border-border/50 bg-background -translate-x-1/2 rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {processedData[hoveredIndex].label}
            </div>
            <div className="text-muted-foreground">
              Change: {processedData[hoveredIndex].value >= 0 ? "+" : ""}
              {processedData[hoveredIndex].value.toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              Running Total: {processedData[hoveredIndex].end.toLocaleString()}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"
import { area, curveBasis } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface FunnelSeries {
  name: string
  values: number[] // Value at each stage
  color?: string
}

export interface FunnelChartProps extends BaseChartProps {
  /** Stage labels */
  stages: string[]
  /** Data series - each series flows through all stages */
  series: FunnelSeries[]
  /** Color scheme */
  colorScheme?: "orange" | "blue" | "purple" | "green" | "pink" | "custom"
  /** Show stage markers (vertical lines) */
  showStageMarkers?: boolean
  /** Show value pills at each stage */
  showValuePills?: boolean
  /** Position of value pills */
  pillPosition?: "top" | "bottom" | "both" | "center"
  /** Animate on mount */
  animate?: boolean
  /** Animation duration */
  animationDuration?: number
  /** Value formatter */
  valueFormatter?: (value: number) => string
  /** Minimum height for the flow (prevents collapse to zero) */
  minFlowHeight?: number
  /** How much of vertical space to use (0-1, default 0.85) */
  flowExpansion?: number
  /** Click handler */
  onSeriesClick?: (series: FunnelSeries, stageIndex: number) => void
}

// Legacy interface for backwards compatibility
export interface FunnelDataPoint {
  label: string
  value: number
  color?: string
}

// Color schemes matching the images - gradient from light to dark
const COLOR_SCHEMES = {
  orange: [
    "#FEF3C7", // lightest
    "#FDE68A",
    "#FCD34D",
    "#FBBF24",
    "#F59E0B",
    "#D97706",
    "#B45309",
    "#92400E", // darkest
  ],
  blue: [
    "#DBEAFE",
    "#BFDBFE",
    "#93C5FD",
    "#60A5FA",
    "#3B82F6",
    "#2563EB",
    "#1D4ED8",
    "#1E40AF",
  ],
  purple: [
    "#EDE9FE",
    "#DDD6FE",
    "#C4B5FD",
    "#A78BFA",
    "#8B5CF6",
    "#7C3AED",
    "#6D28D9",
    "#5B21B6",
  ],
  green: [
    "#D1FAE5",
    "#A7F3D0",
    "#6EE7B7",
    "#34D399",
    "#10B981",
    "#059669",
    "#047857",
    "#065F46",
  ],
  pink: [
    "#FCE7F3",
    "#FBCFE8",
    "#F9A8D4",
    "#F472B6",
    "#EC4899",
    "#DB2777",
    "#BE185D",
    "#9D174D",
  ],
  custom: [],
}

export function FunnelChart({
  stages,
  series,
  config,
  className,
  width = 900,
  height = 320,
  margin = { top: 45, right: 40, bottom: 45, left: 40 },
  showTooltip = true,
  colorScheme = "orange",
  showStageMarkers = true,
  showValuePills = true,
  pillPosition = "both",
  animate = true,
  animationDuration = 1000,
  valueFormatter = (v) => v.toLocaleString(),
  minFlowHeight = 12,
  flowExpansion = 0.98,
  onSeriesClick,
}: FunnelChartProps) {
  const [animationProgress, setAnimationProgress] = React.useState(
    animate ? 0 : 1
  )
  const [hoveredSeries, setHoveredSeries] = React.useState<number | null>(null)
  const [tooltipData, setTooltipData] = React.useState<{
    x: number
    y: number
    seriesIndex: number
    stageIndex: number
  } | null>(null)
  const containerRef = React.useRef<HTMLDivElement>(null)
  const gradientId = React.useId().replace(/:/g, "")

  // Animation
  React.useEffect(() => {
    if (!animate) return
    const startTime = Date.now()
    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      setAnimationProgress(eased)
      if (progress < 1) requestAnimationFrame(animateFrame)
    }
    requestAnimationFrame(animateFrame)
  }, [animate, animationDuration])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const centerY = innerHeight / 2

  const stageCount = stages.length
  const seriesCount = series.length

  // Get color for series - innermost is lightest, outermost is darkest
  const getColor = (index: number): string => {
    if (colorScheme === "custom" && series[index]?.color) {
      return series[index].color!
    }
    const scheme = COLOR_SCHEMES[colorScheme] || COLOR_SCHEMES.orange
    // Map series index to color - distribute evenly across scheme
    const colorIndex = Math.floor(
      (index / Math.max(seriesCount - 1, 1)) * (scheme.length - 1)
    )
    return scheme[Math.min(colorIndex, scheme.length - 1)]
  }

  // Calculate max total at any stage for scaling
  const maxStageTotal = React.useMemo(() => {
    let max = 0
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      let total = 0
      for (const s of series) {
        total += s.values[stageIndex] || 0
      }
      max = Math.max(max, total)
    }
    return max || 1
  }, [series, stageCount])

  // Y scale - maps values to heights (half the inner height for symmetric expansion)
  // flowExpansion controls how much of the available vertical space is used
  const yScale = scaleLinear()
    .domain([0, maxStageTotal])
    .range([0, (innerHeight / 2) * flowExpansion])

  // Generate intermediate points for smoother curves
  const generateIntermediatePoints = (
    x1: number,
    y1: number,
    x2: number,
    y2: number,
    segments: number = 3
  ): [number, number][] => {
    const points: [number, number][] = []
    for (let i = 0; i <= segments; i++) {
      const t = i / segments
      // Use ease-in-out for natural flow
      const easeT = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2
      points.push([x1 + (x2 - x1) * t, y1 + (y2 - y1) * easeT])
    }
    return points
  }

  // Generate flowing area paths for each series
  const areaPaths = React.useMemo(() => {
    const paths: {
      topPath: string
      bottomPath: string
      color: string
      seriesIndex: number
    }[] = []

    // Calculate heights at each stage for each series
    const seriesHeights: number[][] = []
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      const heights: number[] = []
      for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
        const value = series[seriesIndex].values[stageIndex] || 0
        const height = Math.max(
          yScale(value) * animationProgress,
          minFlowHeight * animationProgress
        )
        heights.push(height)
      }
      seriesHeights.push(heights)
    }

    // Calculate cumulative offsets at each stage
    const cumulativeOffsets: number[][] = []
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      const offsets: number[] = [0]
      let cumulative = 0
      for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
        cumulative += seriesHeights[stageIndex][seriesIndex]
        offsets.push(cumulative)
      }
      cumulativeOffsets.push(offsets)
    }

    // Create area path for each series (from innermost to outermost)
    for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
      // Build points with intermediate values for smooth curves
      const topPoints: [number, number][] = []
      const bottomPoints: [number, number][] = []

      for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
        const stageX = (stageIndex / (stageCount - 1)) * innerWidth
        const offset = cumulativeOffsets[stageIndex][seriesIndex]
        const height = seriesHeights[stageIndex][seriesIndex]

        // Top edge (above center line)
        const topY = centerY - offset - height
        // Bottom edge (below center line)
        const bottomY = centerY + offset + height

        if (stageIndex > 0) {
          // Add intermediate points for smooth transitions
          const prevStageX = ((stageIndex - 1) / (stageCount - 1)) * innerWidth
          const prevOffset = cumulativeOffsets[stageIndex - 1][seriesIndex]
          const prevHeight = seriesHeights[stageIndex - 1][seriesIndex]
          const prevTopY = centerY - prevOffset - prevHeight
          const prevBottomY = centerY + prevOffset + prevHeight

          const intermediateTop = generateIntermediatePoints(
            prevStageX,
            prevTopY,
            stageX,
            topY,
            4
          )
          const intermediateBottom = generateIntermediatePoints(
            prevStageX,
            prevBottomY,
            stageX,
            bottomY,
            4
          )

          // Skip first point to avoid duplication
          topPoints.push(...intermediateTop.slice(1))
          bottomPoints.push(...intermediateBottom.slice(1))
        } else {
          topPoints.push([stageX, topY])
          bottomPoints.push([stageX, bottomY])
        }
      }

      // Create SVG path using D3 area
      const areaGenerator = area<[number, number]>()
        .x((d) => d[0])
        .y0((_, i) => bottomPoints[i]?.[1] ?? centerY)
        .y1((d) => d[1])
        .curve(curveBasis)

      const pathData = areaGenerator(topPoints)

      if (pathData) {
        paths.push({
          topPath: pathData,
          bottomPath: pathData, // Same path works due to y0/y1
          color: getColor(seriesIndex),
          seriesIndex,
        })
      }
    }

    // Reverse so innermost (first series) is rendered last (on top visually matches images)
    return paths.reverse()
  }, [
    series,
    seriesCount,
    stageCount,
    innerWidth,
    centerY,
    yScale,
    animationProgress,
    minFlowHeight,
    flowExpansion,
    colorScheme,
  ])

  // Calculate stage X positions
  const stagePositions = React.useMemo(() => {
    return stages.map((_, i) => (i / (stageCount - 1)) * innerWidth)
  }, [stages, stageCount, innerWidth])

  // Calculate values to display in pills (top and bottom at each stage)
  const pillData = React.useMemo(() => {
    return stages.map((_, stageIndex) => {
      // Get values sorted by their position (outer to inner for display)
      const stageValues = series.map((s, i) => ({
        value: s.values[stageIndex] || 0,
        seriesIndex: i,
      }))

      // Top half shows first half of series, bottom shows second half
      const midPoint = Math.ceil(seriesCount / 2)
      const topSeries = stageValues.slice(0, midPoint)
      const bottomSeries = stageValues.slice(midPoint)

      return {
        x: stagePositions[stageIndex],
        topValue: topSeries.reduce((sum, s) => sum + s.value, 0),
        bottomValue: bottomSeries.reduce((sum, s) => sum + s.value, 0),
        totalValue: stageValues.reduce((sum, s) => sum + s.value, 0),
      }
    })
  }, [series, seriesCount, stages, stagePositions])

  // Handle mouse move for tooltip
  const handleMouseMove = (e: React.MouseEvent, seriesIndex: number) => {
    if (!showTooltip) return
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      // Determine which stage we're over
      const relativeX = e.clientX - rect.left - margin.left
      const stageIndex = Math.round((relativeX / innerWidth) * (stageCount - 1))
      setTooltipData({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
        seriesIndex,
        stageIndex: Math.max(0, Math.min(stageCount - 1, stageIndex)),
      })
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("relative !aspect-auto", className)}
    >
      <div
        ref={containerRef}
        className="relative w-full"
        style={{ aspectRatio: `${width}/${height}` }}
      >
        <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
          {/* Gradient definitions for each series */}
          <defs>
            {series.map((_, i) => {
              const color = getColor(i)
              return (
                <linearGradient
                  key={i}
                  id={`flow-gradient-${gradientId}-${i}`}
                  x1="0%"
                  y1="0%"
                  x2="100%"
                  y2="0%"
                >
                  <stop offset="0%" stopColor={color} stopOpacity={1} />
                  <stop offset="50%" stopColor={color} stopOpacity={1} />
                  <stop offset="100%" stopColor={color} stopOpacity={1} />
                </linearGradient>
              )
            })}
            {/* Drop shadow filter */}
            <filter
              id={`pill-shadow-${gradientId}`}
              x="-20%"
              y="-20%"
              width="140%"
              height="140%"
            >
              <feDropShadow
                dx="0"
                dy="1"
                stdDeviation="2"
                floodOpacity="0.15"
              />
            </filter>
          </defs>

          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Background fade for depth effect */}
            <rect
              x={0}
              y={0}
              width={innerWidth}
              height={innerHeight}
              fill="transparent"
            />

            {/* Flowing area paths - rendered from outermost to innermost */}
            {areaPaths.map(({ topPath, color, seriesIndex }, i) => (
              <path
                key={i}
                d={topPath}
                fill={`url(#flow-gradient-${gradientId}-${seriesIndex})`}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredSeries !== null &&
                    hoveredSeries !== seriesIndex &&
                    "opacity-30"
                )}
                onMouseEnter={() => setHoveredSeries(seriesIndex)}
                onMouseMove={(e) => handleMouseMove(e, seriesIndex)}
                onMouseLeave={() => {
                  setHoveredSeries(null)
                  setTooltipData(null)
                }}
                onClick={() => {
                  if (tooltipData) {
                    onSeriesClick?.(series[seriesIndex], tooltipData.stageIndex)
                  }
                }}
              />
            ))}

            {/* Stage markers (vertical lines) - only between stages, not at edges */}
            {showStageMarkers &&
              stagePositions
                .slice(1, -1)
                .map((x, i) => (
                  <line
                    key={i}
                    x1={x}
                    y1={0}
                    x2={x}
                    y2={innerHeight}
                    stroke="white"
                    strokeWidth={3}
                    strokeOpacity={0.9}
                    className="pointer-events-none"
                  />
                ))}

            {/* Value pills */}
            {showValuePills &&
              animationProgress > 0.6 &&
              pillData.map(({ x, topValue, bottomValue, totalValue }, i) => (
                <g
                  key={i}
                  style={{
                    opacity: Math.min(1, (animationProgress - 0.6) * 2.5),
                  }}
                >
                  {/* Top pill */}
                  {(pillPosition === "top" || pillPosition === "both") &&
                    topValue > 0 && (
                      <g transform={`translate(${x}, -25)`}>
                        <rect
                          x={-40}
                          y={-14}
                          width={80}
                          height={28}
                          rx={14}
                          fill="white"
                          filter={`url(#pill-shadow-${gradientId})`}
                        />
                        <text
                          textAnchor="middle"
                          dominantBaseline="middle"
                          className="text-sm font-semibold"
                          fill="#374151"
                        >
                          {valueFormatter(topValue)}
                        </text>
                      </g>
                    )}

                  {/* Bottom pill */}
                  {(pillPosition === "bottom" || pillPosition === "both") &&
                    bottomValue > 0 && (
                      <g transform={`translate(${x}, ${innerHeight + 25})`}>
                        <rect
                          x={-40}
                          y={-14}
                          width={80}
                          height={28}
                          rx={14}
                          fill="white"
                          filter={`url(#pill-shadow-${gradientId})`}
                        />
                        <text
                          textAnchor="middle"
                          dominantBaseline="middle"
                          className="text-sm font-semibold"
                          fill="#374151"
                        >
                          {valueFormatter(bottomValue)}
                        </text>
                      </g>
                    )}

                  {/* Center pill - shows total */}
                  {pillPosition === "center" && (
                    <g transform={`translate(${x}, ${centerY})`}>
                      <rect
                        x={-40}
                        y={-14}
                        width={80}
                        height={28}
                        rx={14}
                        fill="white"
                        filter={`url(#pill-shadow-${gradientId})`}
                      />
                      <text
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="text-sm font-semibold"
                        fill="#374151"
                      >
                        {valueFormatter(totalValue)}
                      </text>
                    </g>
                  )}
                </g>
              ))}
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && tooltipData && (
          <div
            className="pointer-events-none absolute z-50 -translate-x-1/2 -translate-y-full"
            style={{
              left: tooltipData.x,
              top: tooltipData.y - 10,
            }}
          >
            <div className="bg-popover text-popover-foreground rounded-lg border px-3 py-2 shadow-lg">
              <div className="flex items-center gap-2">
                <div
                  className="h-3 w-3 rounded-sm"
                  style={{ backgroundColor: getColor(tooltipData.seriesIndex) }}
                />
                <span className="font-medium">
                  {series[tooltipData.seriesIndex]?.name}
                </span>
              </div>
              <div className="mt-1 text-sm">
                <span className="text-muted-foreground">Stage: </span>
                <span className="font-medium">
                  {stages[tooltipData.stageIndex]}
                </span>
              </div>
              <div className="text-sm">
                <span className="text-muted-foreground">Value: </span>
                <span className="font-semibold">
                  {valueFormatter(
                    series[tooltipData.seriesIndex]?.values[
                      tooltipData.stageIndex
                    ] || 0
                  )}
                </span>
              </div>
            </div>
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { interpolateRgb } from "d3-interpolate"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface HeatmapDataPoint {
  x: string | number
  y: string | number
  value: number
}

export interface HeatmapChartProps extends BaseChartProps {
  data: HeatmapDataPoint[]
  xLabels?: string[]
  yLabels?: string[]
  colorScale?: [string, string] | [string, string, string]
  showValues?: boolean
  cellRadius?: number
  cellPadding?: number
  xAxisLabel?: string
  yAxisLabel?: string
  valueFormat?: (value: number) => string
}

export function HeatmapChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 80, bottom: 50, left: 60 },
  showTooltip = true,
  colorScale = ["#f0f9ff", "#0ea5e9"],
  showValues = false,
  cellRadius = 2,
  cellPadding = 1,
  xAxisLabel,
  yAxisLabel,
  valueFormat = (v) => v.toFixed(1),
}: HeatmapChartProps) {
  const [hoveredCell, setHoveredCell] = React.useState<{
    x: string | number
    y: string | number
  } | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Extract unique labels
  const xLabelsUnique = React.useMemo(() => {
    const labels = [...new Set(data.map((d) => String(d.x)))]
    return labels.sort()
  }, [data])

  const yLabelsUnique = React.useMemo(() => {
    const labels = [...new Set(data.map((d) => String(d.y)))]
    return labels.sort()
  }, [data])

  // Scales
  const xScale = scaleBand()
    .domain(xLabelsUnique)
    .range([0, innerWidth])
    .padding(cellPadding / 100)

  const yScale = scaleBand()
    .domain(yLabelsUnique)
    .range([0, innerHeight])
    .padding(cellPadding / 100)

  // Value scale for colors
  const values = data.map((d) => d.value)
  const minValue = Math.min(...values)
  const maxValue = Math.max(...values)

  const valueScale = scaleLinear()
    .domain(
      colorScale.length === 3
        ? [minValue, (minValue + maxValue) / 2, maxValue]
        : [minValue, maxValue]
    )
    .range([0, 1])

  // Color interpolator
  const getColor = React.useCallback(
    (value: number) => {
      const t = valueScale(value)
      if (colorScale.length === 3) {
        if (t < 0.5) {
          return interpolateRgb(colorScale[0], colorScale[1])(t * 2)
        }
        return interpolateRgb(colorScale[1], colorScale[2])((t - 0.5) * 2)
      }
      return interpolateRgb(colorScale[0], colorScale[1])(t)
    },
    [colorScale, valueScale]
  )

  // Create data matrix for quick lookup
  const dataMatrix = React.useMemo(() => {
    const matrix: Record<string, Record<string, number>> = {}
    data.forEach((d) => {
      const xKey = String(d.x)
      const yKey = String(d.y)
      if (!matrix[yKey]) matrix[yKey] = {}
      matrix[yKey][xKey] = d.value
    })
    return matrix
  }, [data])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Cells */}
          {yLabelsUnique.map((yLabel) =>
            xLabelsUnique.map((xLabel) => {
              const value = dataMatrix[yLabel]?.[xLabel]
              if (value === undefined) return null

              const x = xScale(xLabel) ?? 0
              const y = yScale(yLabel) ?? 0
              const cellWidth = xScale.bandwidth()
              const cellHeight = yScale.bandwidth()
              const isHovered =
                hoveredCell?.x === xLabel && hoveredCell?.y === yLabel

              return (
                <g key={`${xLabel}-${yLabel}`}>
                  <rect
                    x={x}
                    y={y}
                    width={cellWidth}
                    height={cellHeight}
                    fill={getColor(value)}
                    rx={cellRadius}
                    ry={cellRadius}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      isHovered && "stroke-foreground stroke-2"
                    )}
                    onMouseEnter={() =>
                      setHoveredCell({ x: xLabel, y: yLabel })
                    }
                    onMouseLeave={() => setHoveredCell(null)}
                  />

                  {/* Value label */}
                  {showValues && cellWidth > 30 && cellHeight > 20 && (
                    <text
                      x={x + cellWidth / 2}
                      y={y + cellHeight / 2}
                      textAnchor="middle"
                      dominantBaseline="middle"
                      className={cn(
                        "pointer-events-none text-[10px] font-medium",
                        valueScale(value) > 0.5
                          ? "fill-white"
                          : "fill-foreground"
                      )}
                    >
                      {valueFormat(value)}
                    </text>
                  )}
                </g>
              )
            })
          )}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>

        {/* Color legend */}
        <g transform={`translate(${width - margin.right + 15}, ${margin.top})`}>
          <defs>
            <linearGradient id="heatmap-gradient" x1="0" y1="1" x2="0" y2="0">
              <stop offset="0%" stopColor={colorScale[0]} />
              {colorScale.length === 3 && (
                <stop offset="50%" stopColor={colorScale[1]} />
              )}
              <stop
                offset="100%"
                stopColor={colorScale[colorScale.length - 1]}
              />
            </linearGradient>
          </defs>
          <rect
            width={15}
            height={innerHeight}
            fill="url(#heatmap-gradient)"
            rx={2}
          />
          <text
            x={20}
            y={0}
            dominantBaseline="hanging"
            className="fill-muted-foreground text-[10px]"
          >
            {maxValue.toFixed(1)}
          </text>
          <text
            x={20}
            y={innerHeight}
            dominantBaseline="auto"
            className="fill-muted-foreground text-[10px]"
          >
            {minValue.toFixed(1)}
          </text>
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredCell && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              (xScale(String(hoveredCell.x)) ?? 0) +
              xScale.bandwidth() / 2,
            top: margin.top + (yScale(String(hoveredCell.y)) ?? 0),
          }}
        >
          <div className="border-border/50 bg-background -mt-2 -translate-x-1/2 -translate-y-full rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {String(hoveredCell.x)} × {String(hoveredCell.y)}
            </div>
            <div className="text-muted-foreground">
              Value:{" "}
              {valueFormat(
                dataMatrix[String(hoveredCell.y)]?.[String(hoveredCell.x)] ?? 0
              )}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { contours } from "d3-contour"
import { geoPath } from "d3-geo"
import { interpolateRgb } from "d3-interpolate"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartGrid } from "../chart-grid"

export interface ContourPoint {
  x: number
  y: number
  value?: number
}

export interface ContourChartProps extends BaseChartProps {
  /** 2D array of z values (grid data) */
  data: number[][]
  /** Optional scatter points to display on top */
  points?: ContourPoint[]
  xDomain?: [number, number]
  yDomain?: [number, number]
  /** Number of contour levels */
  levels?: number
  /** Color scale - supports 2-7 colors for gradient */
  colorScale?: string[]
  /** Show filled contour regions */
  showFill?: boolean
  /** Show contour lines */
  showLines?: boolean
  /** Contour line width */
  lineWidth?: number
  /** Line color (defaults to darker shade of fill) */
  lineColor?: string
  /** Show data point markers */
  showMarkers?: boolean
  /** Marker symbol: "x", "cross", "circle", "diamond" */
  markerSymbol?: "x" | "cross" | "circle" | "diamond"
  /** Marker size */
  markerSize?: number
  /** Marker color */
  markerColor?: string
  xAxisLabel?: string
  yAxisLabel?: string
  /** Smoothing factor for contours (higher = smoother) */
  bandwidth?: number
}

// Predefined color scales
export const CONTOUR_COLOR_SCALES = {
  // Rainbow (like the image)
  rainbow: ["#0000ff", "#00ffff", "#00ff00", "#ffff00", "#ff8000", "#ff0000"],
  // Viridis-like
  viridis: ["#440154", "#414487", "#2a788e", "#22a884", "#7ad151", "#fde725"],
  // Cool to warm
  coolwarm: [
    "#3b4cc0",
    "#7092c0",
    "#aac7fd",
    "#f7f7f7",
    "#f4a582",
    "#d6604d",
    "#b40426",
  ],
  // Ocean
  ocean: [
    "#023858",
    "#045a8d",
    "#0570b0",
    "#3690c0",
    "#74a9cf",
    "#a6bddb",
    "#d0d1e6",
  ],
  // Thermal
  thermal: ["#0d0887", "#6a00a8", "#b12a90", "#e16462", "#fca636", "#f0f921"],
  // Default blue
  blue: ["#eff6ff", "#3b82f6", "#1e3a8a"],
}

export function ContourChart({
  data,
  points,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 80, bottom: 50, left: 60 },
  showGrid = true,
  showTooltip = true,
  xDomain,
  yDomain,
  levels = 10,
  colorScale = CONTOUR_COLOR_SCALES.rainbow,
  showFill = true,
  showLines = true,
  lineWidth = 0.5,
  lineColor,
  showMarkers = true,
  markerSymbol = "x",
  markerSize = 8,
  markerColor = "#333333",
  xAxisLabel,
  yAxisLabel,
  bandwidth = 1,
}: ContourChartProps) {
  const [mousePos, setMousePos] = React.useState<{
    x: number
    y: number
    value: number
  } | null>(null)

  const gradientId = React.useId().replace(/:/g, "")
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  const rows = data.length
  const cols = data[0]?.length ?? 0

  // Calculate value range
  const allValues = data.flat()
  const minValue = Math.min(...allValues)
  const maxValue = Math.max(...allValues)

  // Scales
  const actualXDomain = xDomain ?? [0, cols - 1]
  const actualYDomain = yDomain ?? [0, rows - 1]

  const xScale = scaleLinear().domain(actualXDomain).range([0, innerWidth])
  const yScale = scaleLinear().domain(actualYDomain).range([innerHeight, 0])
  const valueScale = scaleLinear().domain([minValue, maxValue]).range([0, 1])

  // Color interpolator for multiple colors
  const getColor = React.useCallback(
    (value: number) => {
      const t = valueScale(value)
      const n = colorScale.length - 1
      const segment = Math.min(Math.floor(t * n), n - 1)
      const localT = t * n - segment
      return interpolateRgb(
        colorScale[segment],
        colorScale[segment + 1]
      )(localT)
    },
    [colorScale, valueScale]
  )

  // Generate contours using d3-contour
  const contourGenerator = React.useMemo(() => {
    const thresholds = Array.from(
      { length: levels + 1 },
      (_, i) => minValue + ((maxValue - minValue) * i) / levels
    )
    return contours().size([cols, rows]).thresholds(thresholds)
  }, [cols, rows, levels, minValue, maxValue])

  // Flatten data for d3-contour (expects 1D array)
  const flatData = React.useMemo(() => {
    // d3-contour expects row-major order, bottom to top
    const result: number[] = []
    for (let j = rows - 1; j >= 0; j--) {
      for (let i = 0; i < cols; i++) {
        result.push(data[j][i])
      }
    }
    return result
  }, [data, rows, cols])

  // Generate contour paths
  const contourPaths = React.useMemo(() => {
    return contourGenerator(flatData)
  }, [contourGenerator, flatData])

  // Path generator that transforms from grid coords to screen coords
  const pathGenerator = React.useMemo(() => {
    return geoPath().projection({
      stream: (s) => ({
        point: (x: number, y: number) => {
          // Transform from grid coordinates to screen coordinates
          const screenX = (x / (cols - 1)) * innerWidth
          const screenY = innerHeight - (y / (rows - 1)) * innerHeight
          s.point(screenX, screenY)
        },
        lineStart: () => s.lineStart(),
        lineEnd: () => s.lineEnd(),
        polygonStart: () => s.polygonStart(),
        polygonEnd: () => s.polygonEnd(),
        sphere: () => {},
      }),
    })
  }, [cols, rows, innerWidth, innerHeight])

  // Generate marker path based on symbol
  const getMarkerPath = React.useCallback(
    (cx: number, cy: number) => {
      const s = markerSize / 2
      switch (markerSymbol) {
        case "x":
          return `M${cx - s},${cy - s}L${cx + s},${cy + s}M${cx + s},${cy - s}L${cx - s},${cy + s}`
        case "cross":
          return `M${cx},${cy - s}L${cx},${cy + s}M${cx - s},${cy}L${cx + s},${cy}`
        case "diamond":
          return `M${cx},${cy - s}L${cx + s},${cy}L${cx},${cy + s}L${cx - s},${cy}Z`
        case "circle":
        default:
          return ""
      }
    },
    [markerSize, markerSymbol]
  )

  // Handle mouse move
  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    const rect = e.currentTarget.getBoundingClientRect()
    const x = e.clientX - rect.left - margin.left
    const y = e.clientY - rect.top - margin.top

    if (x < 0 || x > innerWidth || y < 0 || y > innerHeight) {
      setMousePos(null)
      return
    }

    const dataX = Math.round((x / innerWidth) * (cols - 1))
    const dataY = Math.round(((innerHeight - y) / innerHeight) * (rows - 1))

    if (dataX >= 0 && dataX < cols && dataY >= 0 && dataY < rows) {
      setMousePos({
        x: xScale.invert(x),
        y: yScale.invert(y),
        value: data[dataY]?.[dataX] ?? 0,
      })
    }
  }

  // Generate grid points for markers
  const gridPoints = React.useMemo(() => {
    if (!showMarkers && !points) return []

    if (points) {
      return points.map((p) => ({
        x: xScale(p.x),
        y: yScale(p.y),
        value: p.value,
      }))
    }

    // Generate markers at grid intersections
    const result: { x: number; y: number; value: number }[] = []
    for (let j = 0; j < rows; j++) {
      for (let i = 0; i < cols; i++) {
        const gridX =
          actualXDomain[0] +
          ((actualXDomain[1] - actualXDomain[0]) * i) / (cols - 1)
        const gridY =
          actualYDomain[0] +
          ((actualYDomain[1] - actualYDomain[0]) * j) / (rows - 1)
        result.push({
          x: xScale(gridX),
          y: yScale(gridY),
          value: data[j][i],
        })
      }
    }
    return result
  }, [
    showMarkers,
    points,
    data,
    rows,
    cols,
    xScale,
    yScale,
    actualXDomain,
    actualYDomain,
  ])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-full w-full"
        onMouseMove={handleMouseMove}
        onMouseLeave={() => setMousePos(null)}
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Clip path for contours */}
          <defs>
            <clipPath id={`clip-${gradientId}`}>
              <rect width={innerWidth} height={innerHeight} />
            </clipPath>
          </defs>

          {/* Filled contours */}
          {showFill && (
            <g clipPath={`url(#clip-${gradientId})`}>
              {contourPaths.map((contour, i) => (
                <path
                  key={`fill-${i}`}
                  d={pathGenerator(contour) || ""}
                  fill={getColor(contour.value)}
                  fillOpacity={0.9}
                  className="pointer-events-none"
                />
              ))}
            </g>
          )}

          {/* Contour lines */}
          {showLines && (
            <g clipPath={`url(#clip-${gradientId})`}>
              {contourPaths.map((contour, i) => (
                <path
                  key={`line-${i}`}
                  d={pathGenerator(contour) || ""}
                  fill="none"
                  stroke={lineColor || "rgba(0,0,0,0.3)"}
                  strokeWidth={lineWidth}
                  className="pointer-events-none"
                />
              ))}
            </g>
          )}

          {/* Grid */}
          {showGrid && (
            <ChartGrid
              xScale={xScale}
              yScale={yScale}
              width={innerWidth}
              height={innerHeight}
            />
          )}

          {/* Data point markers */}
          {showMarkers &&
            gridPoints.map((point, i) =>
              markerSymbol === "circle" ? (
                <circle
                  key={`marker-${i}`}
                  cx={point.x}
                  cy={point.y}
                  r={markerSize / 2}
                  fill="none"
                  stroke={markerColor}
                  strokeWidth={1.5}
                  className="pointer-events-none"
                />
              ) : (
                <path
                  key={`marker-${i}`}
                  d={getMarkerPath(point.x, point.y)}
                  fill="none"
                  stroke={markerColor}
                  strokeWidth={1.5}
                  className="pointer-events-none"
                />
              )
            )}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>

        {/* Color legend */}
        <g transform={`translate(${width - margin.right + 15}, ${margin.top})`}>
          <defs>
            <linearGradient
              id={`contour-gradient-${gradientId}`}
              x1="0"
              y1="1"
              x2="0"
              y2="0"
            >
              {colorScale.map((color, i) => (
                <stop
                  key={i}
                  offset={`${(i / (colorScale.length - 1)) * 100}%`}
                  stopColor={color}
                />
              ))}
            </linearGradient>
          </defs>
          <rect
            width={15}
            height={innerHeight}
            fill={`url(#contour-gradient-${gradientId})`}
            rx={2}
          />
          <text
            x={20}
            y={0}
            dominantBaseline="hanging"
            className="fill-muted-foreground text-[10px]"
          >
            {maxValue.toFixed(1)}
          </text>
          <text
            x={20}
            y={innerHeight}
            dominantBaseline="auto"
            className="fill-muted-foreground text-[10px]"
          >
            {minValue.toFixed(1)}
          </text>
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && mousePos && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: margin.left + xScale(mousePos.x),
            top: margin.top + yScale(mousePos.y),
          }}
        >
          <div className="border-border/50 bg-background -mt-2 -translate-x-1/2 -translate-y-full rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="text-muted-foreground">
              x: {mousePos.x.toFixed(2)}, y: {mousePos.y.toFixed(2)}
            </div>
            <div className="font-medium">
              Value: {mousePos.value.toFixed(2)}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"
import { curveLinearClosed, lineRadial } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartLegend, type LegendItem } from "../chart-legend"

export interface RadarChartDataPoint {
  axis: string
  value: number
}

export interface RadarChartSeries {
  name: string
  data: RadarChartDataPoint[]
  color?: string
  fillOpacity?: number
}

export interface RadarChartProps extends BaseChartProps {
  data: RadarChartSeries[]
  maxValue?: number
  levels?: number
  showDots?: boolean
  dotSize?: number
  fillOpacity?: number
  strokeWidth?: number
  showLabels?: boolean
  labelOffset?: number
}

export function RadarChart({
  data,
  config,
  className,
  width = 500,
  height = 500,
  margin = { top: 50, right: 50, bottom: 50, left: 50 },
  showTooltip = true,
  showLegend = true,
  maxValue: maxValueProp,
  levels = 5,
  showDots = true,
  dotSize = 4,
  fillOpacity = 0.25,
  strokeWidth = 2,
  showLabels = true,
  labelOffset = 20,
}: RadarChartProps) {
  const [hoveredSeries, setHoveredSeries] = React.useState<string | null>(null)
  const [hoveredPoint, setHoveredPoint] = React.useState<{
    series: string
    axis: string
    value: number
    x: number
    y: number
  } | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const centerX = innerWidth / 2
  const centerY = innerHeight / 2

  // Get all axes from data
  const axes = React.useMemo(() => {
    const axisSet = new Set<string>()
    data.forEach((series) => {
      series.data.forEach((d) => axisSet.add(d.axis))
    })
    return Array.from(axisSet)
  }, [data])

  const angleSlice = (2 * Math.PI) / axes.length

  // Calculate max value
  const maxValue =
    maxValueProp ??
    Math.max(...data.flatMap((s) => s.data.map((d) => d.value))) * 1.1

  // Radial scale
  const rScale = scaleLinear().domain([0, maxValue]).range([0, radius])

  // Get coordinates for a data point
  const getPoint = (axis: string, value: number) => {
    const index = axes.indexOf(axis)
    const angle = angleSlice * index - Math.PI / 2
    const r = rScale(value)
    return {
      x: centerX + r * Math.cos(angle),
      y: centerY + r * Math.sin(angle),
    }
  }

  // Generate radar area path
  const radarLine = lineRadial<RadarChartDataPoint>()
    .angle((d) => axes.indexOf(d.axis) * angleSlice)
    .radius((d) => rScale(d.value))
    .curve(curveLinearClosed)

  // Legend items
  const legendItems: LegendItem[] = data.map((series, i) => ({
    name: series.name,
    color:
      series.color ??
      config?.[series.name]?.color ??
      `var(--chart-${(i % 5) + 1})`,
  }))

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Background circles */}
          {Array.from({ length: levels }, (_, i) => {
            const levelRadius = (radius / levels) * (i + 1)
            return (
              <circle
                key={i}
                cx={centerX}
                cy={centerY}
                r={levelRadius}
                fill="none"
                stroke="currentColor"
                strokeWidth={0.5}
                strokeOpacity={0.3}
                className="text-border"
              />
            )
          })}

          {/* Axis lines */}
          {axes.map((axis, i) => {
            const angle = angleSlice * i - Math.PI / 2
            const x2 = centerX + radius * Math.cos(angle)
            const y2 = centerY + radius * Math.sin(angle)
            return (
              <line
                key={axis}
                x1={centerX}
                y1={centerY}
                x2={x2}
                y2={y2}
                stroke="currentColor"
                strokeWidth={0.5}
                strokeOpacity={0.3}
                className="text-border"
              />
            )
          })}

          {/* Axis labels */}
          {showLabels &&
            axes.map((axis, i) => {
              const angle = angleSlice * i - Math.PI / 2
              const x = centerX + (radius + labelOffset) * Math.cos(angle)
              const y = centerY + (radius + labelOffset) * Math.sin(angle)
              return (
                <text
                  key={axis}
                  x={x}
                  y={y}
                  textAnchor="middle"
                  dominantBaseline="middle"
                  className="fill-muted-foreground text-[11px]"
                >
                  {axis}
                </text>
              )
            })}

          {/* Level labels */}
          {Array.from({ length: levels }, (_, i) => {
            const levelValue = (maxValue / levels) * (i + 1)
            const levelRadius = (radius / levels) * (i + 1)
            return (
              <text
                key={i}
                x={centerX + 4}
                y={centerY - levelRadius}
                className="fill-muted-foreground text-[9px]"
                dominantBaseline="middle"
              >
                {levelValue.toFixed(0)}
              </text>
            )
          })}

          {/* Radar areas */}
          {data.map((series, seriesIndex) => {
            const color =
              series.color ??
              config?.[series.name]?.color ??
              `var(--chart-${(seriesIndex % 5) + 1})`
            const isHovered =
              hoveredSeries === null || hoveredSeries === series.name

            // Sort data by axis order
            const sortedData = axes.map((axis) => {
              const point = series.data.find((d) => d.axis === axis)
              return { axis, value: point?.value ?? 0 }
            })

            return (
              <g key={series.name}>
                {/* Area */}
                <path
                  d={radarLine(sortedData) ?? ""}
                  transform={`translate(${centerX}, ${centerY})`}
                  fill={color}
                  fillOpacity={series.fillOpacity ?? fillOpacity}
                  stroke={color}
                  strokeWidth={strokeWidth}
                  className={cn(
                    "transition-opacity duration-200",
                    !isHovered && "opacity-30"
                  )}
                />

                {/* Dots */}
                {showDots &&
                  sortedData.map((d) => {
                    const point = getPoint(d.axis, d.value)
                    const isPointHovered =
                      hoveredPoint?.series === series.name &&
                      hoveredPoint?.axis === d.axis

                    return (
                      <circle
                        key={d.axis}
                        cx={point.x}
                        cy={point.y}
                        r={isPointHovered ? dotSize * 1.5 : dotSize}
                        fill={color}
                        stroke="white"
                        strokeWidth={1.5}
                        className={cn(
                          "cursor-pointer transition-all duration-200",
                          !isHovered && "opacity-30"
                        )}
                        onMouseEnter={() =>
                          setHoveredPoint({
                            series: series.name,
                            axis: d.axis,
                            value: d.value,
                            x: point.x,
                            y: point.y,
                          })
                        }
                        onMouseLeave={() => setHoveredPoint(null)}
                      />
                    )
                  })}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredPoint && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: margin.left + hoveredPoint.x,
            top: margin.top + hoveredPoint.y - 10,
          }}
        >
          <div className="border-border/50 bg-background -translate-x-1/2 -translate-y-full rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">{hoveredPoint.series}</div>
            <div className="text-muted-foreground">
              {hoveredPoint.axis}: {hoveredPoint.value.toLocaleString()}
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      {showLegend && data.length > 1 && (
        <ChartLegend items={legendItems} onItemHover={setHoveredSeries} />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import {
  hierarchy,
  treemap,
  treemapBinary,
  treemapDice,
  treemapSlice,
  treemapSquarify,
} from "d3-hierarchy"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface TreemapNode {
  name: string
  value?: number
  children?: TreemapNode[]
  color?: string
}

export interface TreemapChartProps extends BaseChartProps {
  data: TreemapNode
  tile?: "squarify" | "binary" | "slice" | "dice"
  padding?: number
  paddingInner?: number
  paddingOuter?: number
  round?: boolean
  showLabels?: boolean
  labelMinSize?: number
}

const tileMap = {
  squarify: treemapSquarify,
  binary: treemapBinary,
  slice: treemapSlice,
  dice: treemapDice,
}

export function TreemapChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 10, right: 10, bottom: 10, left: 10 },
  showTooltip = true,
  tile = "squarify",
  padding = 1,
  paddingInner = 2,
  paddingOuter = 2,
  round = true,
  showLabels = true,
  labelMinSize = 30,
}: TreemapChartProps) {
  const [hoveredNode, setHoveredNode] = React.useState<TreemapNode | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create hierarchy and compute treemap layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
      .sum((d) => d.value ?? 0)
      .sort((a, b) => (b.value ?? 0) - (a.value ?? 0))

    const treemapLayout = treemap<TreemapNode>()
      .size([innerWidth, innerHeight])
      .tile(tileMap[tile])
      .padding(padding)
      .paddingInner(paddingInner)
      .paddingOuter(paddingOuter)
      .round(round)

    return treemapLayout(h)
  }, [
    data,
    innerWidth,
    innerHeight,
    tile,
    padding,
    paddingInner,
    paddingOuter,
    round,
  ])

  // Get all leaves (nodes with values)
  const leaves = root.leaves()

  // Calculate total value for percentages
  const totalValue = root.value ?? 1

  // Generate colors based on depth and index
  const getColor = (node: (typeof leaves)[number], index: number): string => {
    const nodeData = node.data
    if (nodeData.color) return nodeData.color
    if (config?.[nodeData.name]?.color) return config[nodeData.name].color!

    // Use different shades based on parent
    const parentIndex = node.parent
      ? leaves.filter((l) => l.parent === node.parent).indexOf(node)
      : index
    return `var(--chart-${(parentIndex % 5) + 1})`
  }

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {leaves.map((node, index) => {
            const nodeData = node.data
            const x = node.x0
            const y = node.y0
            const w = node.x1 - node.x0
            const h = node.y1 - node.y0
            const color = getColor(node, index)
            const isHovered = hoveredNode === nodeData

            return (
              <g key={`${nodeData.name}-${index}`}>
                <rect
                  x={x}
                  y={y}
                  width={w}
                  height={h}
                  fill={color}
                  rx={2}
                  ry={2}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    hoveredNode !== null && !isHovered && "opacity-60",
                    isHovered && "brightness-110"
                  )}
                  onMouseEnter={() => setHoveredNode(nodeData)}
                  onMouseLeave={() => setHoveredNode(null)}
                />

                {/* Label */}
                {showLabels && w >= labelMinSize && h >= labelMinSize && (
                  <text
                    x={x + w / 2}
                    y={y + h / 2}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    className="pointer-events-none fill-white text-[11px] font-medium"
                    style={{ textShadow: "0 1px 2px rgba(0,0,0,0.3)" }}
                  >
                    {nodeData.name.length > w / 8
                      ? `${nodeData.name.slice(0, Math.floor(w / 8))}...`
                      : nodeData.name}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredNode && (
        <div
          className="pointer-events-none fixed z-50"
          style={{
            left: "50%",
            top: "50%",
            transform: "translate(-50%, -50%)",
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-3 py-2 text-sm shadow-xl">
            <div className="font-medium">{hoveredNode.name}</div>
            <div className="text-muted-foreground">
              Value: {(hoveredNode.value ?? 0).toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              {(((hoveredNode.value ?? 0) / totalValue) * 100).toFixed(1)}% of
              total
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { hierarchy, partition } from "d3-hierarchy"
import { scaleOrdinal } from "d3-scale"
import { arc } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface SunburstNode {
  name: string
  value?: number
  children?: SunburstNode[]
  color?: string
}

export interface SunburstChartProps extends BaseChartProps {
  data: SunburstNode
  innerRadius?: number
  padAngle?: number
  cornerRadius?: number
  showLabels?: boolean
  labelMinAngle?: number
}

export function SunburstChart({
  data,
  config,
  className,
  width = 500,
  height = 500,
  margin = { top: 10, right: 10, bottom: 10, left: 10 },
  showTooltip = true,
  innerRadius = 50,
  padAngle = 0.01,
  cornerRadius = 3,
  showLabels = true,
  labelMinAngle = 0.1,
}: SunburstChartProps) {
  const [hoveredNode, setHoveredNode] = React.useState<SunburstNode | null>(
    null
  )
  const [breadcrumbs, setBreadcrumbs] = React.useState<SunburstNode[]>([])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const centerX = innerWidth / 2
  const centerY = innerHeight / 2

  // Create hierarchy and partition layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
      .sum((d) => d.value ?? 0)
      .sort((a, b) => (b.value ?? 0) - (a.value ?? 0))

    const partitionLayout = partition<SunburstNode>().size([
      2 * Math.PI,
      radius,
    ])

    return partitionLayout(h)
  }, [data, radius])

  // Calculate depth for color scaling
  const maxDepth = root.height

  // Color scale based on depth
  const depthColors = [
    "var(--chart-1)",
    "var(--chart-2)",
    "var(--chart-3)",
    "var(--chart-4)",
    "var(--chart-5)",
  ]

  const getColor = (node: typeof root, index: number): string => {
    const nodeData = node.data
    if (nodeData.color) return nodeData.color
    if (config?.[nodeData.name]?.color) return config[nodeData.name].color!
    return depthColors[node.depth % depthColors.length]
  }

  // Arc generator
  const arcGenerator = arc<typeof root>()
    .startAngle((d) => d.x0)
    .endAngle((d) => d.x1)
    .padAngle(padAngle)
    .innerRadius((d) =>
      d.depth === 0 ? 0 : innerRadius + (d.y0 / radius) * (radius - innerRadius)
    )
    .outerRadius((d) =>
      d.depth === 0
        ? innerRadius
        : innerRadius + (d.y1 / radius) * (radius - innerRadius)
    )
    .cornerRadius(cornerRadius)

  // Label arc for positioning
  const labelArc = arc<typeof root>()
    .startAngle((d) => d.x0)
    .endAngle((d) => d.x1)
    .innerRadius(
      (d) => innerRadius + ((d.y0 + d.y1) / 2 / radius) * (radius - innerRadius)
    )
    .outerRadius(
      (d) => innerRadius + ((d.y0 + d.y1) / 2 / radius) * (radius - innerRadius)
    )

  // Get all descendants for rendering
  const descendants = root.descendants()

  // Handle hover
  const handleHover = (node: typeof root | null) => {
    if (!node) {
      setHoveredNode(null)
      setBreadcrumbs([])
      return
    }
    setHoveredNode(node.data)
    setBreadcrumbs(
      node
        .ancestors()
        .reverse()
        .map((n) => n.data)
    )
  }

  // Total value for percentage calculation
  const totalValue = root.value ?? 1

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g
          transform={`translate(${margin.left + centerX}, ${margin.top + centerY})`}
        >
          {descendants.map((node, index) => {
            const nodeData = node.data
            const color = getColor(node, index)
            const isHovered = hoveredNode === nodeData
            const isAncestor = breadcrumbs.includes(nodeData)
            const angle = node.x1 - node.x0

            return (
              <g key={`${nodeData.name}-${node.depth}-${index}`}>
                <path
                  d={arcGenerator(node) ?? ""}
                  fill={color}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    hoveredNode !== null &&
                      !isHovered &&
                      !isAncestor &&
                      "opacity-40",
                    isHovered && "brightness-110"
                  )}
                  onMouseEnter={() => handleHover(node)}
                  onMouseLeave={() => handleHover(null)}
                />

                {/* Label */}
                {showLabels && angle >= labelMinAngle && node.depth > 0 && (
                  <text
                    transform={`translate(${labelArc.centroid(node)}) rotate(${
                      ((node.x0 + node.x1) / 2 - Math.PI / 2) * (180 / Math.PI)
                    })`}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    className="pointer-events-none fill-white text-[9px] font-medium"
                    style={{ textShadow: "0 1px 2px rgba(0,0,0,0.5)" }}
                  >
                    {nodeData.name.length > 10
                      ? `${nodeData.name.slice(0, 8)}...`
                      : nodeData.name}
                  </text>
                )}
              </g>
            )
          })}

          {/* Center label */}
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground text-sm font-medium"
          >
            {hoveredNode?.name ?? data.name}
          </text>
          {hoveredNode && (
            <text
              y={16}
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground text-xs"
            >
              {(hoveredNode.value ?? 0).toLocaleString()}
            </text>
          )}
        </g>
      </svg>

      {/* Breadcrumb trail */}
      {breadcrumbs.length > 1 && (
        <div className="absolute top-2 left-2 flex items-center gap-1 text-xs">
          {breadcrumbs.map((node, i) => (
            <React.Fragment key={i}>
              {i > 0 && <span className="text-muted-foreground">/</span>}
              <span
                className={
                  i === breadcrumbs.length - 1
                    ? "font-medium"
                    : "text-muted-foreground"
                }
              >
                {node.name}
              </span>
            </React.Fragment>
          ))}
        </div>
      )}

      {/* Tooltip */}
      {showTooltip && hoveredNode && breadcrumbs.length > 1 && (
        <div className="border-border/50 bg-background absolute bottom-2 left-2 rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
          <div className="font-medium">{hoveredNode.name}</div>
          <div className="text-muted-foreground">
            Value: {(hoveredNode.value ?? 0).toLocaleString()}
          </div>
          <div className="text-muted-foreground">
            {(((hoveredNode.value ?? 0) / totalValue) * 100).toFixed(1)}% of
            total
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import {
  sankey,
  sankeyCenter,
  sankeyJustify,
  sankeyLeft,
  sankeyLinkHorizontal,
  sankeyRight,
} from "d3-sankey"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface SankeyNode {
  id: string
  name?: string
  color?: string
}

export interface SankeyLink {
  source: string
  target: string
  value: number
  color?: string
}

export interface SankeyChartProps extends BaseChartProps {
  nodes: SankeyNode[]
  links: SankeyLink[]
  nodeWidth?: number
  nodePadding?: number
  nodeAlign?: "left" | "right" | "center" | "justify"
  linkOpacity?: number
  showLabels?: boolean
  showValues?: boolean
}

const alignMap = {
  left: sankeyLeft,
  right: sankeyRight,
  center: sankeyCenter,
  justify: sankeyJustify,
}

interface SankeyComputedNode {
  id: string
  name?: string
  color?: string
  x0: number
  x1: number
  y0: number
  y1: number
  value: number
  sourceLinks: SankeyComputedLink[]
  targetLinks: SankeyComputedLink[]
}

interface SankeyComputedLink {
  source: SankeyComputedNode
  target: SankeyComputedNode
  value: number
  width: number
  y0: number
  y1: number
  color?: string
}

export function SankeyChart({
  nodes,
  links,
  config,
  className,
  width = 800,
  height = 500,
  margin = { top: 20, right: 120, bottom: 20, left: 20 },
  showTooltip = true,
  nodeWidth = 15,
  nodePadding = 20,
  nodeAlign = "justify",
  linkOpacity = 0.5,
  showLabels = true,
  showValues = true,
}: SankeyChartProps) {
  const [hoveredNode, setHoveredNode] =
    React.useState<SankeyComputedNode | null>(null)
  const [hoveredLink, setHoveredLink] =
    React.useState<SankeyComputedLink | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create sankey layout
  const { computedNodes, computedLinks } = React.useMemo(() => {
    // Create node map
    const nodeMap = new Map(nodes.map((n) => [n.id, n]))

    // Create graph
    const sankeyData = {
      nodes: nodes.map((n) => ({ ...n })),
      links: links.map((l) => ({
        source: nodes.findIndex((n) => n.id === l.source),
        target: nodes.findIndex((n) => n.id === l.target),
        value: l.value,
        color: l.color,
      })),
    }

    // Create sankey generator
    const sankeyGenerator = sankey<
      (typeof sankeyData.nodes)[0],
      (typeof sankeyData.links)[0]
    >()
      .nodeId((d) => d.id)
      .nodeWidth(nodeWidth)
      .nodePadding(nodePadding)
      .nodeAlign(alignMap[nodeAlign])
      .extent([
        [0, 0],
        [innerWidth, innerHeight],
      ])

    const result = sankeyGenerator(sankeyData as any)

    return {
      computedNodes: result.nodes as unknown as SankeyComputedNode[],
      computedLinks: result.links as unknown as SankeyComputedLink[],
    }
  }, [nodes, links, innerWidth, innerHeight, nodeWidth, nodePadding, nodeAlign])

  // Get color for node
  const getNodeColor = (node: SankeyComputedNode, index: number): string => {
    if (node.color) return node.color
    const configColor =
      config?.[node.id]?.color ?? config?.[node.name ?? ""]?.color
    if (configColor) return configColor
    return `var(--chart-${(index % 5) + 1})`
  }

  // Link path generator
  const linkPath = sankeyLinkHorizontal()

  // Check if node or its links are highlighted
  const isNodeHighlighted = (node: SankeyComputedNode): boolean => {
    if (!hoveredNode && !hoveredLink) return true
    if (hoveredNode === node) return true
    if (hoveredLink) {
      return hoveredLink.source === node || hoveredLink.target === node
    }
    if (hoveredNode) {
      return (
        hoveredNode.sourceLinks.some((l) => l.target === node) ||
        hoveredNode.targetLinks.some((l) => l.source === node)
      )
    }
    return false
  }

  const isLinkHighlighted = (link: SankeyComputedLink): boolean => {
    if (!hoveredNode && !hoveredLink) return true
    if (hoveredLink === link) return true
    if (hoveredNode) {
      return link.source === hoveredNode || link.target === hoveredNode
    }
    return false
  }

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Links */}
          {computedLinks.map((link, index) => {
            const color =
              link.color ??
              getNodeColor(link.source, computedNodes.indexOf(link.source))
            const highlighted = isLinkHighlighted(link)

            return (
              <path
                key={index}
                d={linkPath(link as any) ?? ""}
                fill="none"
                stroke={color}
                strokeWidth={Math.max(1, link.width)}
                strokeOpacity={highlighted ? linkOpacity : 0.1}
                className={cn(
                  "cursor-pointer transition-all duration-200",
                  hoveredLink === link && "stroke-[2]"
                )}
                onMouseEnter={() => setHoveredLink(link)}
                onMouseLeave={() => setHoveredLink(null)}
              />
            )
          })}

          {/* Nodes */}
          {computedNodes.map((node, index) => {
            const color = getNodeColor(node, index)
            const highlighted = isNodeHighlighted(node)

            return (
              <g key={node.id}>
                <rect
                  x={node.x0}
                  y={node.y0}
                  width={node.x1 - node.x0}
                  height={Math.max(1, node.y1 - node.y0)}
                  fill={color}
                  rx={2}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    !highlighted && "opacity-30"
                  )}
                  onMouseEnter={() => setHoveredNode(node)}
                  onMouseLeave={() => setHoveredNode(null)}
                />

                {/* Node label */}
                {showLabels && (
                  <text
                    x={node.x0 < innerWidth / 2 ? node.x1 + 6 : node.x0 - 6}
                    y={(node.y0 + node.y1) / 2}
                    textAnchor={node.x0 < innerWidth / 2 ? "start" : "end"}
                    dominantBaseline="middle"
                    className={cn(
                      "pointer-events-none text-[11px] transition-opacity duration-200",
                      highlighted
                        ? "fill-foreground"
                        : "fill-muted-foreground/50"
                    )}
                  >
                    {node.name ?? node.id}
                    {showValues && ` (${node.value.toLocaleString()})`}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && (hoveredNode || hoveredLink) && (
        <div className="border-border/50 bg-background absolute bottom-4 left-4 rounded-lg border px-3 py-2 text-sm shadow-xl">
          {hoveredNode && (
            <>
              <div className="font-medium">
                {hoveredNode.name ?? hoveredNode.id}
              </div>
              <div className="text-muted-foreground">
                Value: {hoveredNode.value.toLocaleString()}
              </div>
              <div className="text-muted-foreground mt-1 text-xs">
                Incoming: {hoveredNode.targetLinks.length} | Outgoing:{" "}
                {hoveredNode.sourceLinks.length}
              </div>
            </>
          )}
          {hoveredLink && (
            <>
              <div className="font-medium">
                {hoveredLink.source.name ?? hoveredLink.source.id} →{" "}
                {hoveredLink.target.name ?? hoveredLink.target.id}
              </div>
              <div className="text-muted-foreground">
                Value: {hoveredLink.value.toLocaleString()}
              </div>
            </>
          )}
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface GaugeChartProps extends BaseChartProps {
  /** Current value to display */
  value: number
  /** Minimum value */
  min?: number
  /** Maximum value */
  max?: number
  /** Label text below value */
  label?: string
  /** Units to display after value */
  units?: string
  /** Show the numeric value */
  showValue?: boolean
  /** Gauge variant style */
  variant?:
    | "modern"
    | "speedometer"
    | "segmented"
    | "radial"
    | "minimal"
    | "gradient"
    | "meter"
    | "dashboard"
  /** Arc thickness (as percentage of radius, 0-1) */
  thickness?: number
  /** Primary color or color for filled arc */
  color?: string
  /** Secondary color for gradient */
  colorSecondary?: string
  /** Background arc color */
  bgColor?: string
  /** Segments for segmented variant */
  segments?: Array<{ value: number; color: string; label?: string }>
  /** Show tick marks */
  showTicks?: boolean
  /** Number of tick marks */
  tickCount?: number
  /** Animate on mount */
  animate?: boolean
  /** Animation duration in ms */
  animationDuration?: number
  /** Value formatter */
  valueFormatter?: (value: number) => string
  /** Show percentage instead of value */
  showPercentage?: boolean
}

// Default colors
const COLORS = {
  primary: "#3b82f6",
  success: "#22c55e",
  warning: "#f59e0b",
  danger: "#ef4444",
  muted: "#e5e7eb",
  purple: "#8b5cf6",
  pink: "#ec4899",
}

export function GaugeChart({
  value,
  config,
  className,
  width = 280,
  height = 200,
  margin = { top: 20, right: 20, bottom: 20, left: 20 },
  min = 0,
  max = 100,
  label,
  units,
  showValue = true,
  variant = "modern",
  thickness = 0.15,
  color = COLORS.primary,
  colorSecondary = COLORS.purple,
  bgColor = COLORS.muted,
  segments,
  showTicks = false,
  tickCount = 5,
  animate = true,
  animationDuration = 1000,
  valueFormatter,
  showPercentage = false,
}: GaugeChartProps) {
  const [animatedPercentage, setAnimatedPercentage] = React.useState(0)
  const gradientId = React.useId().replace(/:/g, "")

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Calculate dimensions based on variant
  const isRadial = variant === "radial"
  const centerX = innerWidth / 2
  const centerY = isRadial ? innerHeight / 2 : innerHeight * 0.75
  const radius =
    Math.min(innerWidth / 2, isRadial ? innerHeight / 2 : innerHeight * 0.7) * 0.85
  const strokeWidth = radius * thickness

  // Clamp value and calculate percentage
  const clampedValue = Math.max(min, Math.min(max, value))
  const targetPercentage = (clampedValue - min) / (max - min)

  // Animate percentage
  React.useEffect(() => {
    if (!animate) {
      setAnimatedPercentage(targetPercentage)
      return
    }

    const startTime = Date.now()
    const startPercentage = animatedPercentage

    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      const newPercentage =
        startPercentage + (targetPercentage - startPercentage) * eased
      setAnimatedPercentage(newPercentage)
      if (progress < 1) requestAnimationFrame(animateFrame)
    }
    requestAnimationFrame(animateFrame)
  }, [targetPercentage, animate, animationDuration])

  // Arc calculations for semi-circle (270 degrees for gauge, 360 for radial)
  const arcAngle = isRadial ? 360 : 270
  const circumference = 2 * Math.PI * radius
  const arcLength = (arcAngle / 360) * circumference
  const dashOffset = arcLength * (1 - animatedPercentage)

  // Format value
  const formatValue = (v: number): string => {
    if (valueFormatter) return valueFormatter(v)
    if (showPercentage) return `${Math.round((v / max) * 100)}%`
    if (v >= 1000000) return `${(v / 1000000).toFixed(1)}M`
    if (v >= 1000) return `${(v / 1000).toFixed(1)}K`
    return Math.round(v).toString()
  }

  // Get segment color at current value
  const getSegmentColor = (): string => {
    if (!segments || segments.length === 0) return color
    const currentValue = min + (max - min) * animatedPercentage
    for (let i = segments.length - 1; i >= 0; i--) {
      if (currentValue >= segments[i].value) {
        return segments[i].color
      }
    }
    return segments[0]?.color || color
  }

  // Generate tick positions for semi-circle
  const generateTicks = () => {
    if (!showTicks) return []
    const ticks = []
    const startAngle = -225 // Start from bottom-left
    const totalAngle = 270 // Semi-circle arc

    for (let i = 0; i < tickCount; i++) {
      const angle = startAngle + (totalAngle / (tickCount - 1)) * i
      const rad = (angle * Math.PI) / 180
      const tickValue = min + ((max - min) / (tickCount - 1)) * i

      // Outer tick position
      const outerX = centerX + (radius + 10) * Math.cos(rad)
      const outerY = centerY + (radius + 10) * Math.sin(rad)

      // Inner tick position
      const innerX = centerX + (radius - strokeWidth / 2 - 5) * Math.cos(rad)
      const innerY = centerY + (radius - strokeWidth / 2 - 5) * Math.sin(rad)

      // Label position
      const labelX = centerX + (radius + 25) * Math.cos(rad)
      const labelY = centerY + (radius + 25) * Math.sin(rad)

      ticks.push({ angle, innerX, innerY, outerX, outerY, labelX, labelY, value: tickValue })
    }
    return ticks
  }

  const ticks = generateTicks()

  // Semi-circle arc path (for background)
  const semiCirclePath = `
    M ${centerX - radius} ${centerY}
    A ${radius} ${radius} 0 1 1 ${centerX + radius} ${centerY}
  `

  // Radial uses circle
  const renderRadial = () => (
    <>
      {/* Background circle */}
      <circle
        cx={centerX}
        cy={centerY}
        r={radius}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
      />
      {/* Value arc */}
      <circle
        cx={centerX}
        cy={centerY}
        r={radius}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={circumference}
        strokeDashoffset={circumference * (1 - animatedPercentage)}
        transform={`rotate(-90 ${centerX} ${centerY})`}
        style={{ transition: animate ? "none" : "stroke-dashoffset 0.3s ease" }}
      />
      {/* Center content */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.4 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {(units || label) && (
            <text
              y={radius * 0.3}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.14 }}
            >
              {units || label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Modern clean arc
  const renderModern = () => (
    <>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
        style={{ transition: animate ? "none" : "stroke-dashoffset 0.3s ease" }}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.45 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {units && (
            <text
              y={radius * 0.25}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.14 }}
            >
              {units}
            </text>
          )}
          {label && (
            <text
              y={radius * 0.45}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Gradient arc
  const renderGradient = () => (
    <>
      <defs>
        <linearGradient id={`gauge-gradient-${gradientId}`} x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" stopColor={color} />
          <stop offset="100%" stopColor={colorSecondary} />
        </linearGradient>
      </defs>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Gradient value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={`url(#gauge-gradient-${gradientId})`}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.45 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.35}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Speedometer with needle
  const renderSpeedometer = () => {
    const needleAngle = -225 + 270 * animatedPercentage
    const needleRad = (needleAngle * Math.PI) / 180
    const needleLength = radius * 0.7
    const needleX = centerX + needleLength * Math.cos(needleRad)
    const needleY = centerY + needleLength * Math.sin(needleRad)

    return (
      <>
        {/* Background arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={bgColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
        />
        {/* Value arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeDasharray={arcLength}
          strokeDashoffset={dashOffset}
        />
        {/* Tick marks */}
        {ticks.map((tick, i) => (
          <g key={i}>
            <line
              x1={tick.innerX}
              y1={tick.innerY}
              x2={tick.innerX + (tick.outerX - tick.innerX) * 0.5}
              y2={tick.innerY + (tick.outerY - tick.innerY) * 0.5}
              stroke="currentColor"
              strokeWidth={2}
              className="text-muted-foreground"
            />
            <text
              x={tick.labelX}
              y={tick.labelY}
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground"
              style={{ fontSize: 9 }}
            >
              {formatValue(tick.value)}
            </text>
          </g>
        ))}
        {/* Needle */}
        <line
          x1={centerX}
          y1={centerY}
          x2={needleX}
          y2={needleY}
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={3}
          strokeLinecap="round"
        />
        {/* Needle center */}
        <circle
          cx={centerX}
          cy={centerY}
          r={12}
          fill={segments ? getSegmentColor() : color}
        />
        <circle cx={centerX} cy={centerY} r={6} fill="white" />
        {/* Value below */}
        {showValue && (
          <text
            x={centerX}
            y={centerY + radius * 0.35}
            textAnchor="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.28 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
            {units && (
              <tspan className="fill-muted-foreground font-normal" style={{ fontSize: radius * 0.12 }}>
                {" "}{units}
              </tspan>
            )}
          </text>
        )}
      </>
    )
  }

  // Segmented colored zones
  const renderSegmented = () => {
    const segs = segments || [
      { value: 0, color: COLORS.success },
      { value: 33, color: COLORS.warning },
      { value: 66, color: COLORS.danger },
    ]

    return (
      <>
        {/* Segmented arcs */}
        {segs.map((seg, i) => {
          const nextValue = segs[i + 1]?.value ?? max
          const segStart = (seg.value - min) / (max - min)
          const segEnd = (nextValue - min) / (max - min)
          const segLength = arcLength * (segEnd - segStart)
          const segOffset = arcLength * (1 - segEnd)
          const isActive = animatedPercentage >= segStart

          return (
            <path
              key={i}
              d={semiCirclePath}
              fill="none"
              stroke={seg.color}
              strokeWidth={strokeWidth}
              strokeLinecap="round"
              strokeDasharray={`${segLength - 4} ${arcLength}`}
              strokeDashoffset={-arcLength * segStart}
              opacity={isActive ? 1 : 0.3}
              style={{ transition: "opacity 0.3s ease" }}
            />
          )
        })}
        {/* Indicator dot */}
        {(() => {
          const dotAngle = -225 + 270 * animatedPercentage
          const dotRad = (dotAngle * Math.PI) / 180
          const dotX = centerX + radius * Math.cos(dotRad)
          const dotY = centerY + radius * Math.sin(dotRad)
          return (
            <circle
              cx={dotX}
              cy={dotY}
              r={strokeWidth / 2 + 5}
              fill="white"
              stroke={getSegmentColor()}
              strokeWidth={3}
            />
          )
        })()}
        {/* Center value */}
        {showValue && (
          <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
            <text
              textAnchor="middle"
              dominantBaseline="middle"
              className="font-bold"
              style={{ fontSize: radius * 0.4, fill: getSegmentColor() }}
            >
              {formatValue(min + (max - min) * animatedPercentage)}
            </text>
            {label && (
              <text
                y={radius * 0.3}
                textAnchor="middle"
                className="fill-muted-foreground"
                style={{ fontSize: radius * 0.12 }}
              >
                {label}
              </text>
            )}
          </g>
        )}
      </>
    )
  }

  // Minimal thin arc
  const renderMinimal = () => (
    <>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth * 0.5}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Min label */}
      <text
        x={centerX - radius - 10}
        y={centerY + 15}
        textAnchor="middle"
        className="fill-muted-foreground"
        style={{ fontSize: 10 }}
      >
        {formatValue(min)}
      </text>
      {/* Max label */}
      <text
        x={centerX + radius + 10}
        y={centerY + 15}
        textAnchor="middle"
        className="fill-muted-foreground"
        style={{ fontSize: 10 }}
      >
        {formatValue(max)}
      </text>
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.2})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.5 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.3}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Meter style with ticks outside
  const renderMeter = () => (
    <>
      {/* Outer tick marks */}
      {ticks.map((tick, i) => (
        <g key={i}>
          <line
            x1={tick.outerX}
            y1={tick.outerY}
            x2={tick.outerX + (tick.labelX - tick.outerX) * 0.4}
            y2={tick.outerY + (tick.labelY - tick.outerY) * 0.4}
            stroke="currentColor"
            strokeWidth={i === 0 || i === tickCount - 1 ? 2.5 : 1.5}
            className="text-muted-foreground"
          />
          <text
            x={tick.labelX}
            y={tick.labelY}
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-muted-foreground font-medium"
            style={{ fontSize: 10 }}
          >
            {formatValue(tick.value)}
          </text>
        </g>
      ))}
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.1})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.35 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.25}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.11 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Dashboard card style
  const renderDashboard = () => {
    const percentage = Math.round(animatedPercentage * 100)
    return (
      <>
        {/* Background arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={bgColor}
          strokeWidth={strokeWidth * 1.5}
          strokeLinecap="round"
        />
        {/* Value arc with rounded gradient look */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={strokeWidth * 1.5}
          strokeLinecap="round"
          strokeDasharray={arcLength}
          strokeDashoffset={dashOffset}
        />
        {/* Large percentage in center */}
        {showValue && (
          <g transform={`translate(${centerX}, ${centerY - radius * 0.2})`}>
            <text
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-foreground font-bold"
              style={{ fontSize: radius * 0.6 }}
            >
              {percentage}
              <tspan style={{ fontSize: radius * 0.25 }}>%</tspan>
            </text>
            {label && (
              <text
                y={radius * 0.35}
                textAnchor="middle"
                className="fill-muted-foreground font-medium"
                style={{ fontSize: radius * 0.13 }}
              >
                {label}
              </text>
            )}
          </g>
        )}
      </>
    )
  }

  const renderContent = () => {
    switch (variant) {
      case "speedometer":
        return renderSpeedometer()
      case "segmented":
        return renderSegmented()
      case "radial":
        return renderRadial()
      case "minimal":
        return renderMinimal()
      case "gradient":
        return renderGradient()
      case "meter":
        return renderMeter()
      case "dashboard":
        return renderDashboard()
      default:
        return renderModern()
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("relative !aspect-auto", className)}
    >
      <div
        className="relative w-full"
        style={{ aspectRatio: `${width}/${height}` }}
      >
        <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {renderContent()}
          </g>
        </svg>
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import type { GeoPermissibleObjects } from "d3-geo"
import {
  geoAlbersUsa,
  geoEqualEarth,
  geoMercator,
  geoNaturalEarth1,
  geoPath,
} from "d3-geo"
import { interpolateRgb } from "d3-interpolate"
import { feature } from "topojson-client"
import type { GeometryCollection, Topology } from "topojson-specification"

import { cn } from "@/lib/utils"

export interface GeoFeature {
  type: "Feature"
  properties: {
    name?: string
    iso_a2?: string
    iso_a3?: string
    [key: string]: unknown
  }
  geometry: GeoPermissibleObjects
  id?: string | number
}

export interface GeoJSON {
  type: "FeatureCollection"
  features: GeoFeature[]
}

export interface ChoroplethDataPoint {
  id: string // ISO country code (2 or 3 letter)
  value: number
  label?: string
}

export interface ChoroplethChartProps {
  data: ChoroplethDataPoint[]
  className?: string
  colorScale?: string[]
  showTooltip?: boolean
  showLegend?: boolean
  projection?: "naturalEarth" | "mercator" | "equalEarth" | "albersUsa"
  aspectRatio?: number
  legendTitle?: string
  valueFormatter?: (value: number) => string
  noDataColor?: string
  /** Custom GeoJSON/TopoJSON URL. Defaults to world countries. */
  geoUrl?: string
  /** Object name in TopoJSON (e.g., "states", "countries"). Auto-detected if not provided. */
  topojsonObject?: string
  /** Property name to use as feature ID (e.g., "name", "postal", "iso_a2") */
  idProperty?: string
}

// Default world countries GeoJSON URL
const WORLD_GEOJSON_URL =
  "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json"

// Country-specific GeoJSON/TopoJSON URLs (all CORS-enabled)
export const GEO_URLS = {
  world: "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json",
  usa: "https://cdn.jsdelivr.net/npm/us-atlas@3/states-10m.json",
  india:
    "https://raw.githubusercontent.com/datta07/INDIAN-SHAPEFILES/master/INDIA/INDIA_STATES.geojson",
  china:
    "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/chn.topo.json",
  uk: "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/gbr.topo.json",
  russia:
    "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/rus.topo.json",
  germany:
    "https://raw.githubusercontent.com/isellsoap/deutschlandGeoJSON/master/2_bundeslaender/4_niedrig.geo.json",
  france:
    "https://raw.githubusercontent.com/gregoiredavid/france-geojson/master/regions-version-simplifiee.geojson",
  brazil:
    "https://raw.githubusercontent.com/codeforamerica/click_that_hood/master/public/data/brazil-states.geojson",
} as const

export function ChoroplethChart({
  data,
  className,
  colorScale = ["#dbeafe", "#3b82f6", "#1e40af"],
  showTooltip = true,
  showLegend = true,
  projection = "naturalEarth",
  aspectRatio = 2,
  legendTitle = "Value",
  valueFormatter = (v) => v.toLocaleString(),
  noDataColor = "hsl(var(--muted))",
  geoUrl,
  topojsonObject,
  idProperty,
}: ChoroplethChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [geoData, setGeoData] = React.useState<GeoJSON | null>(null)
  const [loading, setLoading] = React.useState(true)
  const [error, setError] = React.useState<string | null>(null)
  const [hoveredFeature, setHoveredFeature] = React.useState<GeoFeature | null>(
    null
  )
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })
  const gradientId = React.useId().replace(/:/g, "")

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  // Fetch GeoJSON/TopoJSON
  React.useEffect(() => {
    const fetchGeoData = async () => {
      try {
        setLoading(true)
        setError(null)
        const url = geoUrl || WORLD_GEOJSON_URL

        const response = await fetch(url)
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`)
        }

        const jsonData = await response.json()

        // Check if it's TopoJSON (has "objects" property) or GeoJSON
        if (jsonData.type === "Topology" && jsonData.objects) {
          // Convert TopoJSON to GeoJSON
          const topoData = jsonData as Topology<{
            [key: string]: GeometryCollection
          }>

          // Use specified object or find first available (case-insensitive)
          const availableKeys = Object.keys(topoData.objects)
          let objectName = topojsonObject || availableKeys[0]

          // Try case-insensitive match if exact match fails
          if (!topoData.objects[objectName]) {
            const lowerName = objectName.toLowerCase()
            const match = availableKeys.find(
              (k) => k.toLowerCase() === lowerName
            )
            if (match) {
              objectName = match
            } else {
              throw new Error(
                `TopoJSON object "${objectName}" not found. Available: ${availableKeys.join(", ")}`
              )
            }
          }

          const geoJson = feature(
            topoData,
            topoData.objects[objectName]
          ) as unknown as GeoJSON

          setGeoData(geoJson)
        } else if (jsonData.type === "FeatureCollection") {
          // Already GeoJSON
          setGeoData(jsonData as GeoJSON)
        } else {
          throw new Error(
            `Invalid geo data format: ${jsonData.type || "unknown"}`
          )
        }
      } catch (err) {
        const message = err instanceof Error ? err.message : "Unknown error"
        setError(`Failed to load map: ${message}`)
        console.error("Failed to load GeoJSON:", err)
      } finally {
        setLoading(false)
      }
    }
    fetchGeoData()
  }, [geoUrl, topojsonObject])

  const { width, height } = dimensions
  const margin = { top: 10, right: showLegend ? 80 : 20, bottom: 10, left: 10 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)

  // Create data map for quick lookup (support various ID formats)
  const dataMap = React.useMemo(() => {
    const map = new Map<string, ChoroplethDataPoint>()
    data.forEach((d) => {
      map.set(d.id, d) // exact match
      map.set(d.id.toUpperCase(), d)
      map.set(d.id.toLowerCase(), d)
    })
    return map
  }, [data])

  // Calculate value range
  const { minValue, maxValue } = React.useMemo(() => {
    if (data.length === 0) return { minValue: 0, maxValue: 100 }
    const values = data.map((d) => d.value)
    return {
      minValue: Math.min(...values),
      maxValue: Math.max(...values),
    }
  }, [data])

  // Color scale function
  const getColor = React.useCallback(
    (value: number | undefined) => {
      if (value === undefined) return noDataColor
      const range = maxValue - minValue || 1
      const t = (value - minValue) / range

      if (colorScale.length === 2) {
        return interpolateRgb(colorScale[0], colorScale[1])(t)
      }
      if (t < 0.5) {
        return interpolateRgb(colorScale[0], colorScale[1])(t * 2)
      }
      return interpolateRgb(colorScale[1], colorScale[2])((t - 0.5) * 2)
    },
    [colorScale, minValue, maxValue, noDataColor]
  )

  // Get feature value by matching ID
  const getFeatureValue = React.useCallback(
    (feature: GeoFeature) => {
      // If idProperty is specified, use it first
      if (idProperty && feature.properties[idProperty]) {
        const id = String(feature.properties[idProperty])
        const d =
          dataMap.get(id) ||
          dataMap.get(id.toUpperCase()) ||
          dataMap.get(id.toLowerCase())
        if (d) return d.value
      }

      // Try different ID formats (various GeoJSON schemas)
      const ids = [
        feature.id,
        feature.properties.name,
        feature.properties.NAME,
        feature.properties.nom, // French regions
        feature.properties.STNAME_SH, // India states (official)
        feature.properties.iso_a2,
        feature.properties.iso_a3,
        feature.properties.postal,
        feature.properties.code,
        feature.properties.st_nm, // India states (datamaps)
        feature.properties.sigla, // Brazil states
      ].filter(Boolean) as string[]

      for (const id of ids) {
        const d =
          dataMap.get(id) ||
          dataMap.get(id.toUpperCase()) ||
          dataMap.get(id.toLowerCase())
        if (d) return d.value
      }
      return undefined
    },
    [dataMap, idProperty]
  )

  // Create projection
  const projectionFn = React.useMemo(() => {
    if (innerWidth === 0 || innerHeight === 0 || !geoData) return null

    const projections = {
      naturalEarth: geoNaturalEarth1,
      mercator: geoMercator,
      equalEarth: geoEqualEarth,
      albersUsa: geoAlbersUsa,
    }

    const proj = projections[projection]()

    // AlbersUSA has its own built-in scale, others need fitSize
    if (projection === "albersUsa") {
      // Scale to fit container - AlbersUSA is designed for ~960x600
      const scale = Math.min(innerWidth / 960, innerHeight / 600) * 1100
      return proj.scale(scale).translate([innerWidth / 2, innerHeight / 2])
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return proj.fitSize([innerWidth, innerHeight], geoData as any)
  }, [projection, innerWidth, innerHeight, geoData])

  const pathGenerator = React.useMemo(() => {
    if (!projectionFn) return null
    return geoPath().projection(projectionFn)
  }, [projectionFn])

  // Show loading state (use min-height when width not yet measured)
  if (loading) {
    return (
      <div ref={containerRef} className={cn("w-full", className)}>
        <div
          className="bg-muted/20 flex animate-pulse items-center justify-center rounded-lg"
          style={{ height: width > 0 ? width / aspectRatio : 200 }}
        >
          <span className="text-muted-foreground text-sm">Loading map...</span>
        </div>
      </div>
    )
  }

  // Show error state
  if (error || !geoData) {
    return (
      <div ref={containerRef} className={cn("w-full", className)}>
        <div
          className="bg-muted/20 flex items-center justify-center rounded-lg"
          style={{ height: width > 0 ? width / aspectRatio : 200 }}
        >
          <span className="text-muted-foreground text-sm">
            {error || "Failed to load map"}
          </span>
        </div>
      </div>
    )
  }

  // Wait for dimensions to be measured
  if (width === 0 || !pathGenerator) {
    return (
      <div
        ref={containerRef}
        className={cn("min-h-[200px] w-full", className)}
      />
    )
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Map features */}
          {geoData.features.map((feature, index) => {
            const value = getFeatureValue(feature)
            const color = getColor(value)
            const isHovered = hoveredFeature === feature
            const pathD = pathGenerator(feature as any)

            if (!pathD) return null

            return (
              <path
                key={feature.id || index}
                d={pathD}
                fill={color}
                stroke="hsl(var(--background))"
                strokeWidth={isHovered ? 1.5 : 0.5}
                className={cn(
                  "cursor-pointer transition-all duration-150",
                  hoveredFeature !== null && !isHovered && "opacity-70"
                )}
                onMouseEnter={(e) => {
                  setHoveredFeature(feature)
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseMove={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseLeave={() => setHoveredFeature(null)}
              />
            )
          })}
        </g>

        {/* Color legend */}
        {showLegend && (
          <g
            transform={`translate(${width - margin.right + 15}, ${margin.top + 20})`}
          >
            <text
              className="fill-muted-foreground text-[10px] font-medium"
              y={-8}
            >
              {legendTitle}
            </text>
            <defs>
              <linearGradient
                id={`gradient-${gradientId}`}
                x1="0"
                y1="1"
                x2="0"
                y2="0"
              >
                <stop offset="0%" stopColor={colorScale[0]} />
                {colorScale.length === 3 && (
                  <stop offset="50%" stopColor={colorScale[1]} />
                )}
                <stop
                  offset="100%"
                  stopColor={colorScale[colorScale.length - 1]}
                />
              </linearGradient>
            </defs>
            <rect
              width={15}
              height={Math.max(0, innerHeight - 40)}
              fill={`url(#gradient-${gradientId})`}
              rx={2}
            />
            <text
              x={20}
              y={0}
              dominantBaseline="hanging"
              className="fill-muted-foreground text-[10px]"
            >
              {valueFormatter(maxValue)}
            </text>
            <text
              x={20}
              y={Math.max(0, innerHeight - 40)}
              dominantBaseline="auto"
              className="fill-muted-foreground text-[10px]"
            >
              {valueFormatter(minValue)}
            </text>
          </g>
        )}
      </svg>

      {/* Tooltip */}
      {showTooltip &&
        hoveredFeature &&
        (() => {
          const value = getFeatureValue(hoveredFeature)
          const tooltipWidth = 160
          const tooltipHeight = 60
          const padding = 10

          const showOnLeft = tooltipPos.x + tooltipWidth + padding > width
          const showBelow = tooltipPos.y - tooltipHeight - padding < 0

          return (
            <div
              className="pointer-events-none absolute z-50"
              style={{
                left: showOnLeft
                  ? tooltipPos.x - padding
                  : tooltipPos.x + padding,
                top: showBelow
                  ? tooltipPos.y + padding
                  : tooltipPos.y - padding,
                transform: `translate(${showOnLeft ? "-100%" : "0"}, ${showBelow ? "0" : "-100%"})`,
              }}
            >
              <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                <p className="text-foreground text-sm font-medium">
                  {String(
                    hoveredFeature.properties.name ||
                      hoveredFeature.properties.NAME ||
                      hoveredFeature.properties.nom ||
                      hoveredFeature.properties.STNAME_SH ||
                      hoveredFeature.id ||
                      "Unknown"
                  )}
                </p>
                <p className="text-muted-foreground text-sm">
                  {value !== undefined ? (
                    <>
                      {legendTitle}: {valueFormatter(value)}
                    </>
                  ) : (
                    "No data"
                  )}
                </p>
              </div>
            </div>
          )
        })()}
    </div>
  )
}
